        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const error = (await res.json().catch(() => null)) as Record<string, unknown> | null;
        throw new Error((error?.error as string) || "Failed to create integration");
      }
