      );
      const payload = (await res.json()) as {
        error?: string;
        status?: number;
        statusText?: string;
        data?: unknown;
        refreshed?: boolean;
      };
      if (!res.ok) {
        throw new Error(payload.error || "Request failed.");
      }
      return {
