  const activeConnection = connections[0] || null;
  const sessionQuery = useConnectionSession(activeConnection?.id, {
    enabled: showSessionModal,
  });
  const sessionPayload = sessionQuery.data as
    | {
        error?: string;
        cookies?: {
          name?: string;
          value?: string;
          domain?: string;
          path?: string;
          expires?: number;
          httpOnly?: boolean;
          secure?: boolean;
          sameSite?: string;
        }[];
        origins?: { origin?: string; localStorage?: { name?: string; value?: string }[] }[];
        updatedAt?: string | null;
      }
    | null;
  const sessionCookies = sessionPayload?.cookies ?? [];
  const sessionOrigins = sessionPayload?.origins ?? [];
  const sessionUpdatedAt = sessionPayload?.updatedAt ?? null;
  const sessionError = sessionQuery.isError
    ? sessionQuery.error instanceof Error
      ? sessionQuery.error.message
      : "Failed to load session cookies."
    : sessionPayload?.error ?? null;

  useEffect(() => {
    const status = searchParams.get("allegro");
    if (!status) return;
    if (status === "connected") {
      toast("Allegro connected.", { variant: "success" });
    } else {
      const reason = searchParams.get("reason");
      const message = reason
        ? `Allegro authorization failed: ${reason}`
        : "Allegro authorization failed.";
      toast(message, { variant: "error" });
    }
    router.replace("/admin/integrations");
  }, [router, searchParams, toast]);

  useEffect((): void => {
    if (!integrationsQuery.isError) return;
    const message =
      integrationsQuery.error instanceof Error
        ? integrationsQuery.error.message
        : "Failed to load integrations.";
    toast(message, { variant: "error" });
  }, [integrationsQuery.error, integrationsQuery.isError, toast]);

  useEffect((): void => {
    if (!connectionsQuery.isError) return;
    const message =
      connectionsQuery.error instanceof Error
        ? connectionsQuery.error.message
        : "Failed to load connections.";
    toast(message, { variant: "error" });
  }, [connectionsQuery.error, connectionsQuery.isError, toast]);

  useEffect(() => {
    if (!activeIntegration) return;
    if (integrations.find((item: Integration) => item.id === activeIntegration.id)) return;
    setActiveIntegration(null);
  }, [activeIntegration, integrations]);

  useEffect((): void | (() => void) => {
    if (!showPlaywrightSaved) return;
    const timeout = setTimeout(() => setShowPlaywrightSaved(false), 2500);
    return () => clearTimeout(timeout);
  }, [showPlaywrightSaved]);

  const refreshConnections = (integrationId: string): void => {
    void queryClient.invalidateQueries({
      queryKey: ["integration-connections", integrationId],
    });
  };

  useEffect(() => {
    if (connections.length === 0) {
      setEditingConnectionId(null);
      setConnectionForm({ name: "", username: "", password: "" });
      return;
    }
    if (!editingConnectionId) {
      const connection = connections[0];
      if (!connection) return; // Guard against undefined connection

      setEditingConnectionId(connection.id);
      setConnectionForm({
        name: connection.name,
        username: connection.username,
        password: "",
      });
      setPlaywrightSettings({
        headless:
          connection.playwrightHeadless ?? defaultPlaywrightSettings.headless,
        slowMo: connection.playwrightSlowMo ?? defaultPlaywrightSettings.slowMo,
        timeout:
          connection.playwrightTimeout ?? defaultPlaywrightSettings.timeout,
        navigationTimeout:
          connection.playwrightNavigationTimeout ??
          defaultPlaywrightSettings.navigationTimeout,
        humanizeMouse:
          connection.playwrightHumanizeMouse ??
          defaultPlaywrightSettings.humanizeMouse,
        mouseJitter:
          connection.playwrightMouseJitter ??
          defaultPlaywrightSettings.mouseJitter,
        clickDelayMin:
          connection.playwrightClickDelayMin ??
          defaultPlaywrightSettings.clickDelayMin,
        clickDelayMax:
          connection.playwrightClickDelayMax ??
          defaultPlaywrightSettings.clickDelayMax,
        inputDelayMin:
          connection.playwrightInputDelayMin ??
          defaultPlaywrightSettings.inputDelayMin,
        inputDelayMax:
          connection.playwrightInputDelayMax ??
          defaultPlaywrightSettings.inputDelayMax,
        actionDelayMin:
          connection.playwrightActionDelayMin ??
          defaultPlaywrightSettings.actionDelayMin,
        actionDelayMax:
          connection.playwrightActionDelayMax ??
          defaultPlaywrightSettings.actionDelayMax,
        proxyEnabled:
          connection.playwrightProxyEnabled ??
          defaultPlaywrightSettings.proxyEnabled,
        proxyServer:
          connection.playwrightProxyServer ??
          defaultPlaywrightSettings.proxyServer,
        proxyUsername:
          connection.playwrightProxyUsername ??
          defaultPlaywrightSettings.proxyUsername,
        proxyPassword: "",
        emulateDevice:
          connection.playwrightEmulateDevice ??
          defaultPlaywrightSettings.emulateDevice,
        deviceName:
          connection.playwrightDeviceName ??
          defaultPlaywrightSettings.deviceName,
      });
    }
  }, [connections, editingConnectionId]);

  useEffect(() => {
    const loadPlaywrightUtils = async () => {
      if (playwrightPersonas.length === 0) {
        setPlaywrightPersonaId(null);
        return;
      }
      const { findPlaywrightPersonaMatch } = await import("@/features/playwright");
      const match = findPlaywrightPersonaMatch(
        playwrightSettings,
        playwrightPersonas
      );
      setPlaywrightPersonaId(match?.id ?? null);
    };
    loadPlaywrightUtils();
  }, [playwrightPersonas, playwrightSettings]);

  const ensureIntegration = async (
    definition: (typeof integrationDefinitions)[number]
  ): Promise<Integration | null> => {
    let currentIntegrations = integrations;
    if (!currentIntegrations.length && integrationsQuery.isFetching) {
      const refreshed = await integrationsQuery.refetch();
      currentIntegrations = refreshed.data ?? integrationsQuery.data ?? [];
    }
    const existing = currentIntegrations.find(
      (integration: Integration) => integration.slug === definition.slug
    );
    if (existing) return existing;
    try {
      const created = await createIntegrationMutation.mutateAsync({
        name: definition.name,
        slug: definition.slug,
      });
      return created;
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : `Failed to add ${definition.name}`;
      toast(message, { variant: "error" });
      return null;
    }
  };

  const handleIntegrationClick = async (
    definition: (typeof integrationDefinitions)[number]
  ): Promise<void> => {
    const integration = await ensureIntegration(definition);
    if (!integration) return;
    setActiveIntegration(integration);
    refreshConnections(integration.id);
    setIsModalOpen(true);
  };

  const handleSaveConnection = async (): Promise<void> => {
    if (!activeIntegration) return;
    if (!connectionForm.name.trim() || !connectionForm.username.trim()) {
      toast("Connection name and username are required.", {
        variant: "error",
      });
      return;
    }
    if (!editingConnectionId && !connectionForm.password.trim()) {
      toast("Password/Token is required.", { variant: "error" });
      return;
    }
    const payload = {
      name: connectionForm.name.trim(),
      username: connectionForm.username.trim(),
      ...(connectionForm.password.trim()
        ? { password: connectionForm.password.trim() }
        : {}),
    };
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration.id,
        ...(editingConnectionId ? { connectionId: editingConnectionId } : {}),
        payload,
      });
      setConnectionForm({ name: "", username: "", password: "" });
      setEditingConnectionId(null);
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to save connection.";
      toast(message, { variant: "error" });
    }
  };

  const handleAllegroAuthorize = (): void => {
    if (!activeIntegration || !activeConnection) {
      toast("Create an Allegro connection first.", { variant: "error" });
      return;
    }
    window.location.href = `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/authorize`;
  };

  const handleAllegroDisconnect = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) return;
    try {
      await disconnectAllegroMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: activeConnection.id,
      });
      toast("Allegro disconnected.", { variant: "success" });
    } catch (error: unknown) {
      console.error("Failed to disconnect Allegro:", error);
      toast("Failed to disconnect Allegro.", { variant: "error" });
    }
  };

  const handleDeleteConnection = async (connection: IntegrationConnection): Promise<void> => {
    const confirmed = window.confirm(`Delete connection "${connection.name}"?`);
    if (!confirmed) return;
    try {
      await deleteConnectionMutation.mutateAsync({
        integrationId: connection.integrationId,
        connectionId: connection.id,
      });
      if (editingConnectionId === connection.id) {
        setEditingConnectionId(null);
        setConnectionForm({ name: "", username: "", password: "" });
      }
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to delete connection.";
      toast(message, { variant: "error" });
    }
  };

  const handleConnectionTest = async (
    connection: IntegrationConnection,
    type: "test" | "base/test" | "allegro/test",
    title: string
  ): Promise<void> => {
    if (!activeIntegration) return;
    setIsTesting(true);
    setTestLog([]);
    setSelectedStep(null);
    setShowTestLogModal(false);
    setShowTestErrorModal(false);
    setTestError(null);
    setTestErrorMeta(null);
    setLastTestError(null);
    setShowTestSuccessModal(false);
    setTestSuccessMessage(null);

    const requestUrl = `/api/integrations/${activeIntegration.id}/connections/${connection.id}/${type}`;
    const startedAt = performance.now();

    try {
      const payload = (await testConnectionMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: connection.id,
        type,
      })) as TestConnectionResponse & { inventoryCount?: number; profile?: Record<string, unknown> };

      const normalizedSteps = normalizeSteps(payload.steps || []);

      if (normalizedSteps.length) {
        setTestLog(normalizedSteps);
      }

      const durationMs = Math.round(performance.now() - startedAt);

      let extraInfo = "";
      if (type === "base/test" && payload.inventoryCount !== undefined) {
        extraInfo = `\nInventories found: ${payload.inventoryCount}`;
      } else if (type === "allegro/test" && payload.profile) {
        const login = typeof payload.profile.login === "string" ? payload.profile.login : "";
        const name = typeof payload.profile.name === "string" ? payload.profile.name : "";
        const identifier = name || login;
        if (identifier) {
          extraInfo = `\nAccount: ${identifier}`;
        }
      }

      setTestSuccessMessage(
        `${title} succeeded.\nURL: ${requestUrl}\nDuration: ${durationMs}ms${extraInfo}`
      );
      setShowTestSuccessModal(true);
      setTestErrorMeta(null);
      refreshConnections(activeIntegration.id);
    } catch (error: unknown) {
      const durationMs = Math.round(performance.now() - startedAt);
      const message = error instanceof Error ? error.message : "Unknown error";

      const err = error as Error & { data?: TestConnectionResponse };
      const data = err.data;

      let errorMessage = `${title} failed.\nURL: ${requestUrl}\nDuration: ${durationMs}ms\nError: ${message}`;

      if (data) {
        const normalizedSteps = normalizeSteps(data.steps || []);

        const failedStepDetail =
          normalizedSteps.find((step: TestLogEntry) => step.status === "failed")?.detail ||
          "";

        const errorBody =
          data.error || failedStepDetail || "No response body";

        errorMessage = `${title} failed.\nURL: ${requestUrl}\nDuration: ${durationMs}ms\n\nResponse:\n${errorBody}`;

        const steps: TestLogEntry[] = normalizedSteps.length
          ? normalizedSteps.map((step: TestLogEntry) =>
              step.status === "failed" && !step.detail
                ? { ...step, detail: errorMessage }
                : step
            )
          : [
              {
                step: `${title} failed`,
                status: "failed",
                timestamp: new Date().toISOString(),
                detail: errorMessage,
              },
            ];

        setTestLog(steps);
        setTestErrorMeta({
          errorId: data.errorId,
          integrationId: data.integrationId,
          connectionId: data.connectionId,
        });
      } else {
        // Fallback log if no structured data
         setTestLog([
              {
                step: `${title} failed`,
                status: "failed",
                timestamp: new Date().toISOString(),
                detail: errorMessage,
              },
            ]);
      }

      setTestError(errorMessage);
      setLastTestError(errorMessage);
      setShowTestErrorModal(true);
    } finally {
      setIsTesting(false);
    }
  };

  const handleBaselinkerTest = (connection: IntegrationConnection): Promise<void> => {
    return handleConnectionTest(connection, "base/test", "Baselinker connection test");
  };

  const handleAllegroTest = (connection: IntegrationConnection): Promise<void> => {
    return handleConnectionTest(connection, "allegro/test", "Allegro connection test");
  };

  const handleTestConnection = (connection: IntegrationConnection): Promise<void> => {
    return handleConnectionTest(connection, "test", "Connection test");
  };

  const handleOpenSessionModal = (): void => {
    if (!activeConnection) return;
    setShowSessionModal(true);
  };

  const handleSelectPlaywrightPersona = async (personaId: string | null): Promise<void> => {
    if (!personaId) {
      setPlaywrightPersonaId(null);
      return;
    }
    const persona = playwrightPersonas.find((item: PlaywrightPersona) => item.id === personaId);
    if (!persona) return;
    const { buildPlaywrightSettings } = await import("@/features/playwright");
    setPlaywrightPersonaId(persona.id);
    setPlaywrightSettings(buildPlaywrightSettings(persona.settings));
    toast(`Applied persona "${persona.name}".`, { variant: "success" });
  };

  const handleSavePlaywrightSettings = async (): Promise<void> => {
    const connection = connections[0];
    if (!connection) return;

    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration?.id ?? connection.integrationId,
        connectionId: connection.id,
        payload: {
          name: connection.name,
          username: connection.username,
          playwrightHeadless: playwrightSettings.headless,
          playwrightSlowMo: playwrightSettings.slowMo,
          playwrightTimeout: playwrightSettings.timeout,
          playwrightNavigationTimeout: playwrightSettings.navigationTimeout,
          playwrightHumanizeMouse: playwrightSettings.humanizeMouse,
          playwrightMouseJitter: playwrightSettings.mouseJitter,
          playwrightClickDelayMin: playwrightSettings.clickDelayMin,
          playwrightClickDelayMax: playwrightSettings.clickDelayMax,
          playwrightInputDelayMin: playwrightSettings.inputDelayMin,
          playwrightInputDelayMax: playwrightSettings.inputDelayMax,
          playwrightActionDelayMin: playwrightSettings.actionDelayMin,
          playwrightActionDelayMax: playwrightSettings.actionDelayMax,
          playwrightProxyEnabled: playwrightSettings.proxyEnabled,
          playwrightProxyServer: playwrightSettings.proxyServer,
          playwrightProxyUsername: playwrightSettings.proxyUsername,
          playwrightProxyPassword: playwrightSettings.proxyPassword,
          playwrightEmulateDevice: playwrightSettings.emulateDevice,
          playwrightDeviceName: playwrightSettings.deviceName,
        },
      });
      setShowPlaywrightSaved(true);
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : "Failed to save Playwright settings.";
      toast(message, { variant: "error" });
    }
  };

  const handleAllegroSandboxToggle = async (value: boolean): Promise<void> => {
    if (!activeConnection) return;
    if (savingAllegroSandbox) return;
    setSavingAllegroSandbox(true);
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration?.id ?? activeConnection.integrationId,
        connectionId: activeConnection.id,
        payload: {
          name: activeConnection.name,
          username: activeConnection.username,
          allegroUseSandbox: value,
        },
      });
      toast("Allegro sandbox setting updated.", { variant: "success" });
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : "Failed to update Allegro sandbox setting.";
      toast(message, { variant: "error" });
    } finally {
      setSavingAllegroSandbox(false);
    }
  };

  const handleAllegroSandboxConnect = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Create an Allegro connection first.", { variant: "error" });
      return;
    }
    if (savingAllegroSandbox) return;
    setSavingAllegroSandbox(true);
    try {
      await upsertConnectionMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: activeConnection.id,
        payload: {
          name: activeConnection.name,
          username: activeConnection.username,
          allegroUseSandbox: true,
        },
      });
      window.location.href = `/api/integrations/${activeIntegration.id}/connections/${activeConnection.id}/allegro/authorize`;
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to enable Allegro sandbox.";
      toast(message, { variant: "error" });
    } finally {
      setSavingAllegroSandbox(false);
    }
  };

  const handleBaseApiRequest = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Create a Base.com connection first.", { variant: "error" });
      return;
    }
    const methodInput = baseApiMethod.trim();
    const normalizedMethodKey = methodInput.toLowerCase().replace(/\s+/g, "");
    const methodAliases: Record<string, string> = {
      orderlog: "getOrdersLog",
      orderslog: "getOrdersLog",
      getorderslog: "getOrdersLog",
      detailedproductlist: "getInventoryProductsDetailed",
      detailedproducts: "getInventoryProductsDetailed",
      getinventoryproductsdetailed: "getInventoryProductsDetailed",
      detailedproduct: "getInventoryProductDetailed",
      getinventoryproductdetailed: "getInventoryProductDetailed",
      orders: "getOrders",
      getorders: "getOrders",
      inventories: "getInventories",
      getinventories: "getInventories",
      inventoryproducts: "getInventoryProductsList",
      getinventoryproductslist: "getInventoryProductsList",
      productslist: "getProductsList",
      getproductslist: "getProductsList",
      orderstatuses: "getOrderStatusList",
      getorderstatuslist: "getOrderStatusList",
    };
    const method = methodAliases[normalizedMethodKey] ?? methodInput;
    if (!method) {
      toast("Base API method is required.", { variant: "error" });
      return;
    }
    if (method !== methodInput) {
      setBaseApiMethod(method);
    }
    let params: unknown = {};
    if (baseApiParams.trim()) {
      try {
        params = JSON.parse(baseApiParams);
      } catch {
        toast("Parameters must be valid JSON.", { variant: "error" });
        return;
      }
    }
    const normalizedParams = 
      params && typeof params === "object" && !Array.isArray(params)
        ? { ...(params as Record<string, unknown>) }
        : {};
    const inventoryMethods = new Set([
      "getInventoryProductsList",
      "getInventoryProductsData",
      "getInventoryProductsDetailed",
    ]);
    const storageMethods = new Set(["getProductsList", "getProductsData"]);
    if (inventoryMethods.has(method)) {
      const inventoryValue = normalizedParams.inventory_id;
      const hasInventoryId =
        (typeof inventoryValue === "string" && inventoryValue.trim() !== "") ||
        (typeof inventoryValue === "number" && Number.isFinite(inventoryValue));
      const looksEmpty =
        !hasInventoryId || inventoryValue === 0 || inventoryValue === "0";
      if (looksEmpty && activeConnection.baseLastInventoryId) {
        normalizedParams.inventory_id = activeConnection.baseLastInventoryId;
      } else if (looksEmpty) {
        toast("Inventory ID is required. Run getInventories first.", {
          variant: "error",
        });
        return;
      }
    }
    if (storageMethods.has(method)) {
      const storageValue = normalizedParams.storage_id;
      const hasStorageId =
        (typeof storageValue === "string" && storageValue.trim() !== "") ||
        (typeof storageValue === "number" && Number.isFinite(storageValue));
      const looksEmpty =
        !hasStorageId || storageValue === 0 || storageValue === "0";
      if (looksEmpty && activeConnection.baseLastInventoryId) {
        normalizedParams.storage_id = activeConnection.baseLastInventoryId;
      } else if (looksEmpty) {
        toast("Storage ID is required. Run getInventories first.", {
          variant: "error",
        });
        return;
      }
    }
    const normalizedParamsText = JSON.stringify(normalizedParams, null, 2);
    if (normalizedParamsText !== baseApiParams) {
      setBaseApiParams(normalizedParamsText);
    }
    setBaseApiLoading(true);
    setBaseApiError(null);
    setBaseApiResponse(null);
    try {
      const payload = await baseApiRequestMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: activeConnection.id,
        method,
        parameters: normalizedParams,
      });
      setBaseApiResponse({ data: payload.data });
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to send request.";
      setBaseApiError(message);
    } finally {
      setBaseApiLoading(false);
    }
  };

  const handleAllegroApiRequest = async (): Promise<void> => {
    if (!activeIntegration || !activeConnection) {
      toast("Select an integration connection first.", { variant: "error" });
      return;
    }
    const path = allegroApiPath.trim();
    if (!path.startsWith("/")) {
      toast("Allegro API path must start with /", { variant: "error" });
      return;
    }
    let body: unknown = undefined;
    if (allegroApiMethod !== "GET" && allegroApiBody.trim()) {
      try {
        body = JSON.parse(allegroApiBody);
      } catch {
        toast("Request body must be valid JSON.", { variant: "error" });
        return;
      }
    }
    setAllegroApiLoading(true);
    setAllegroApiError(null);
    setAllegroApiResponse(null);
    try {
      const payload = await allegroApiRequestMutation.mutateAsync({
        integrationId: activeIntegration.id,
        connectionId: activeConnection.id,
        method: allegroApiMethod,
        path,
        body,
      });
      setAllegroApiResponse({
        status: payload.status,
        statusText: payload.statusText,
        data: payload.data,
        refreshed: payload.refreshed,
      });
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : "Failed to send request.";
      setAllegroApiError(message);
    } finally {
      setAllegroApiLoading(false);
    }
  };

  return (
    <div className="container mx-auto py-10">
      <IntegrationList
        integrations={integrations}
        onIntegrationClick={(def: (typeof integrationDefinitions)[number]): void => { void handleIntegrationClick(def); }}
      />

      {isModalOpen && activeIntegration && (
        <IntegrationModal
          activeIntegration={activeIntegration}
          connections={connections}
          onClose={(): void => setIsModalOpen(false)}
          editingConnectionId={editingConnectionId}
          setEditingConnectionId={setEditingConnectionId}
          connectionForm={connectionForm}
          setConnectionForm={setConnectionForm}
          onSaveConnection={(): void => { void handleSaveConnection(); }}
          onDeleteConnection={(c: IntegrationConnection): void => { void handleDeleteConnection(c); }}
          onTestConnection={(c: IntegrationConnection): void => { void handleTestConnection(c); }}
          onBaselinkerTest={(c: IntegrationConnection): void => { void handleBaselinkerTest(c); }}
          onAllegroTest={(c: IntegrationConnection): void => { void handleAllegroTest(c); }}
          isTesting={isTesting}
          testLog={testLog}
          onShowLog={(step: TestLogEntry): void => {
            setSelectedStep(
              step.status !== "pending"
                ? (step as TestLogEntry & { status: "ok" | "failed" })
                : null
            );
            setShowTestLogModal(true);
          }}
          showTestLogModal={showTestLogModal}
          onCloseTestLogModal={(): void => setShowTestLogModal(false)}
          selectedStep={selectedStep}
          showTestErrorModal={showTestErrorModal}
          testError={testError}
          testErrorMeta={testErrorMeta}
          onCloseTestErrorModal={(): void => setShowTestErrorModal(false)}
          showTestSuccessModal={showTestSuccessModal}
          testSuccessMessage={testSuccessMessage}
          onCloseTestSuccessModal={(): void => setShowTestSuccessModal(false)}
          showSessionModal={showSessionModal}
          sessionLoading={sessionQuery.isFetching}
          sessionError={sessionError}
          sessionCookies={sessionCookies}
          sessionOrigins={sessionOrigins}
          sessionUpdatedAt={sessionUpdatedAt}
          onCloseSessionModal={(): void => setShowSessionModal(false)}
          playwrightPersonas={playwrightPersonas}
          playwrightPersonasLoading={playwrightPersonasLoading}
          playwrightPersonaId={playwrightPersonaId}
          onSelectPlaywrightPersona={(personaId: string | null): void => { void handleSelectPlaywrightPersona(personaId); }}
          playwrightSettings={playwrightSettings}
          setPlaywrightSettings={setPlaywrightSettings}
          onSavePlaywrightSettings={(): void => { void handleSavePlaywrightSettings(); }}
          showPlaywrightSaved={showPlaywrightSaved}
          onOpenSessionModal={(): void => { void handleOpenSessionModal(); }}
          savingAllegroSandbox={savingAllegroSandbox}
          onToggleAllegroSandbox={(v: boolean): void => { void handleAllegroSandboxToggle(v); }}
          onAllegroAuthorize={(): void => { void handleAllegroAuthorize(); }}
          onAllegroDisconnect={(): void => { void handleAllegroDisconnect(); }}
          onAllegroSandboxConnect={(): void => { void handleAllegroSandboxConnect(); }}
          baseApiMethod={baseApiMethod}
          setBaseApiMethod={setBaseApiMethod}
          baseApiParams={baseApiParams}
          setBaseApiParams={setBaseApiParams}
          baseApiLoading={baseApiLoading}
          baseApiError={baseApiError}
          baseApiResponse={baseApiResponse}
          onBaseApiRequest={(): void => { void handleBaseApiRequest(); }}
          allegroApiMethod={allegroApiMethod}
          setAllegroApiMethod={setAllegroApiMethod}
          allegroApiPath={allegroApiPath}
          setAllegroApiPath={setAllegroApiPath}
          allegroApiBody={allegroApiBody}
          setAllegroApiBody={setAllegroApiBody}
          allegroApiLoading={allegroApiLoading}
          allegroApiError={allegroApiError}
          allegroApiResponse={allegroApiResponse}
          onAllegroApiRequest={(): void => { void handleAllegroApiRequest(); }}
        />
      )}
    </div>
  );
}

export default function IntegrationsPage(): React.JSX.Element {
  return (
    <Suspense fallback={<div>Loading integrations...</div>}>
      <IntegrationsContent />
    </Suspense>
  );
}

import type { CurrencyOption, CountryOption, Language } from "../../../shared/types/internationalization";

export async function getCurrencies(): Promise<CurrencyOption[]> {
  const res = await fetch("/api/currencies");
  if (!res.ok) throw new Error("Failed to fetch currencies.");
  return (await res.json()) as CurrencyOption[];
}

export async function getCountries(): Promise<CountryOption[]> {
  const res = await fetch("/api/countries");
  if (!res.ok) throw new Error("Failed to fetch countries.");
  return (await res.json()) as CountryOption[];
}

export async function getLanguages(): Promise<Language[]> {
  const res = await fetch("/api/languages");
  if (!res.ok) throw new Error("Failed to fetch languages.");
  return (await res.json()) as Language[];
}

export async function deleteCurrency(id: string): Promise<void> {
  const res = await fetch(`/api/currencies/${id}`, { method: "DELETE" });
  if (!res.ok) throw new Error("Failed to delete currency.");
}

export async function deleteCountry(id: string): Promise<void> {
  const res = await fetch(`/api/countries/${id}`, { method: "DELETE" });
  if (!res.ok) throw new Error("Failed to delete country.");
}

export async function deleteLanguage(id: string): Promise<void> {
  const res = await fetch(`/api/languages/${id}`, { method: "DELETE" });
  if (!res.ok) throw new Error("Failed to delete language.");
}

export async function saveCurrency(id: string | undefined, data: Partial<CurrencyOption>): Promise<CurrencyOption> {
  const res = await fetch(id ? `/api/currencies/${id}` : "/api/currencies", {
    method: id ? "PUT" : "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) throw new Error("Failed to save currency.");
  return res.json();
}

export async function saveCountry(id: string | undefined, data: Partial<CountryOption>): Promise<CountryOption> {
  const res = await fetch(id ? `/api/countries/${id}` : "/api/countries", {
    method: id ? "PUT" : "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) throw new Error("Failed to save country.");
  return res.json();
}

export async function saveLanguage(id: string | undefined, data: Partial<Language>): Promise<Language> {
  const res = await fetch(id ? `/api/languages/${id}` : "/api/languages", {
    method: id ? "PUT" : "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });
  if (!res.ok) throw new Error("Failed to save language.");
  return res.json();
}

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import * as api from "../api";
import type { CurrencyOption, CountryOption, Language } from "../../../shared/types/internationalization";

export const internationalizationKeys = {
  all: ["internationalization"] as const,
  currencies: () => [...internationalizationKeys.all, "currencies"] as const,
  countries: () => [...internationalizationKeys.all, "countries"] as const,
  languages: () => [...internationalizationKeys.all, "languages"] as const,
};

export function useCurrencies() {
  return useQuery({
    queryKey: internationalizationKeys.currencies(),
    queryFn: api.getCurrencies,
  });
}

export function useCountries() {
  return useQuery({
    queryKey: internationalizationKeys.countries(),
    queryFn: api.getCountries,
  });
}

export function useLanguages() {
  return useQuery({
    queryKey: internationalizationKeys.languages(),
    queryFn: api.getLanguages,
  });
}

export function useDeleteCurrencyMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteCurrency(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.currencies() });
    },
  });
}

export function useDeleteCountryMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteCountry(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.countries() });
    },
  });
}

export function useDeleteLanguageMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteLanguage(id),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.languages() });
    },
  });
}

export function useSaveCurrencyMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id?: string; data: Partial<CurrencyOption> }) => api.saveCurrency(id, data),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.currencies() });
    },
  });
}

export function useSaveCountryMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id?: string; data: Partial<CountryOption> & { currencyIds?: string[] } }) => api.saveCountry(id, data),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.countries() });
    },
  });
}

export function useSaveLanguageMutation() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id?: string; data: Partial<Language> & { countryIds?: string[] } }) => api.saveLanguage(id, data),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: internationalizationKeys.languages() });
    },
  });
}

"use client";

import { Button, Input, Tabs, TabsContent, TabsList, TabsTrigger, useToast, AppModal, ModalShell, SectionHeader, SectionPanel } from "@/shared/ui";
import { Suspense, useMemo, useState } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";
import { Loader2, RefreshCcw, Trash2, XCircle, Eye } from "lucide-react";
import ProductListingJobsPanel from "@/features/jobs/components/ProductListingJobsPanel";
import type { ProductAiJob } from "@/shared/types/jobs";
import type { ProductAiJobsPanelProps } from "@/features/jobs/types/jobs-ui";
import { useProductAiJobs } from "@/features/jobs/hooks/useJobQueries";
import { 
  useProductAiJobMutation, 
  useDeleteProductAiJobMutation, 
  useClearProductAiJobsMutation 
} from "@/features/jobs/hooks/useJobMutations";

type JobMeta = {
  payload: Record<string, unknown> | null;
  graph?: Record<string, unknown>;
  context?: Record<string, unknown>;
  entityType?: string;
  entityId?: string;
  pathName?: string;
  pathId?: string;
  nodeTitle?: string;
  source?: string;
  displayEntity: string;
  subEntity?: string;
};

export default function ProductAiJobsPanel({
  title = "AI Jobs",
  description = "Monitor AI, import, and export jobs across the platform.",
  showTabs = true,
}: ProductAiJobsPanelProps): React.JSX.Element {
  const { toast } = useToast();
  const searchParams = useSearchParams();
  const [query, setQuery] = useState("");
  const [selectedJob, setSelectedJob] = useState<ProductAiJob | null>(null);

  // Queries
  const jobsQuery = useProductAiJobs("all");
  const jobs = useMemo(() => jobsQuery.data?.jobs || [], [jobsQuery.data]);

  // Mutations
  const actionMutation = useProductAiJobMutation();
  const deleteMutation = useDeleteProductAiJobMutation();
  const clearMutation = useClearProductAiJobsMutation();

  const getPayload = (job: ProductAiJob): Record<string, unknown> | null => {
    return job.payload && typeof job.payload === "object"
      ? (job.payload as Record<string, unknown>)
      : null;
  };

  const getJobMeta = (job: ProductAiJob): JobMeta => {
    const payload = getPayload(job);
    const graph = payload?.graph as Record<string, unknown> | undefined;
    const context = payload?.context as Record<string, unknown> | undefined;
    const entityType =
      (payload?.entityType as string | undefined) ??
      (context?.entityType as string | undefined) ??
      (graph?.entityType as string | undefined);
    const entityId =
      (payload?.entityId as string | undefined) ??
      (context?.entityId as string | undefined) ??
      (payload?.productId as string | undefined) ??
      job.productId;
    const pathName = (graph?.pathName as string | undefined) ?? undefined;
    const pathId = (graph?.pathId as string | undefined) ?? undefined;
    const nodeTitle = (graph?.nodeTitle as string | undefined) ?? undefined;
    const source = (payload?.source as string | undefined) ?? undefined;
    const displayEntity =
      job.product?.name_en || job.product?.sku
        ? `${job.product?.name_en || "Untitled"} (${job.product?.sku || "N/A"})`
        : entityType || entityId
          ? `${entityType ?? "entity"} · ${entityId ?? "unknown"}`
          : "N/A";
    const subEntity = job.product?.sku
      ? `SKU: ${job.product.sku}`
      : pathName || pathId
        ? `Path: ${pathName ?? pathId}`
        : entityId
          ? `ID: ${entityId}`
          : source
            ? `Source: ${source}`
            : undefined;

    return {
      payload,
      graph,
      context,
      entityType,
      entityId,
      pathName,
      pathId,
      nodeTitle,
      source,
      displayEntity,
      subEntity,
    };
  };

  const defaultTab = useMemo((): string => {
    if (!showTabs) return "ai";
    const tab = searchParams?.get("tab") ?? "ai";
    return ["ai", "import", "export"].includes(tab) ? tab : "ai";
  }, [searchParams, showTabs]);

  const cancelJob = async (jobId: string): Promise<void> => {
    try {
      await actionMutation.mutateAsync({ jobId, action: "cancel" });
      toast("Job canceled", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to cancel job.", { variant: "error" });
    }
  };

  const deleteJob = async (jobId: string): Promise<void> => {
    try {
      await deleteMutation.mutateAsync(jobId);
      toast("Job deleted", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete job.", { variant: "error" });
    }
  };

  const clearCompleted = async (): Promise<void> => {
    if (!window.confirm("Delete all completed jobs? This cannot be undone.")) return;
    try {
      await clearMutation.mutateAsync({ scope: "terminal" });
      toast("Jobs cleared", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete completed jobs.", { variant: "error" });
    }
  };

  const clearAllJobs = async (): Promise<void> => {
    if (!window.confirm("Delete ALL AI jobs (including running/pending)?")) return;
    try {
      await clearMutation.mutateAsync({ scope: "all" });
      toast("All jobs deleted", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to delete all jobs.", { variant: "error" });
    }
  };

  const filteredJobs = jobs.filter((job: ProductAiJob) => {
    const meta = getJobMeta(job);
    const searchStr = query.toLowerCase();
    return [
      job.id,
      job.status,
      job.type,
      meta.entityType,
      meta.entityId,
      meta.pathName,
      meta.pathId,
      meta.nodeTitle,
      meta.source,
      job.product?.name_en,
      job.product?.sku,
    ].some((val) => val && String(val).toLowerCase().includes(searchStr));
  });

  const aiContent = (
    <>
      <div className="flex flex-wrap items-center justify-between gap-3">
        <Input
          placeholder="Search by ID, entity, path, or model..."
          value={query}
          onChange={(e: React.ChangeEvent<HTMLInputElement>): void => setQuery(e.target.value)}
          className="max-w-md bg-gray-900 border-border text-white"
        />
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={(): void => { void jobsQuery.refetch(); }} disabled={jobsQuery.isFetching}>
            <RefreshCcw className={`mr-2 h-4 w-4 ${jobsQuery.isFetching ? "animate-spin" : ""}`} />
            Refresh
          </Button>
          <Button variant="destructive" size="sm" onClick={(): void => { void clearCompleted(); }} disabled={clearMutation.isPending}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear Finished
          </Button>
          <Button variant="destructive" size="sm" onClick={(): void => { void clearAllJobs(); }} disabled={clearMutation.isPending}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear All
          </Button>
        </div>
      </div>

      <div className="rounded-lg border border-border bg-card overflow-hidden">
        <table className="w-full text-left text-sm text-gray-300">
          <thead className="bg-gray-900 text-xs uppercase text-gray-500">
            <tr>
              <th className="px-4 py-3">Entity</th>
              <th className="px-4 py-3">Type / ID</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">Timing</th>
              <th className="px-4 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {filteredJobs.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-4 py-10 text-center text-gray-500">
                  {jobsQuery.isLoading ? "Loading jobs..." : "No jobs found."}
                </td>
              </tr>
            ) : (
              filteredJobs.map((job: ProductAiJob) => {
                const meta = getJobMeta(job);
                return (
                  <tr key={job.id} className="hover:bg-card/50">
                  <td className="px-4 py-4">
                    <div className="font-medium text-white">{meta.displayEntity}</div>
                    {meta.subEntity && (
                      <div className="text-xs text-gray-500">{meta.subEntity}</div>
                    )}
                  </td>
                  <td className="px-4 py-4">
                    <div className="text-xs font-mono">{job.type}</div>
                    <div className="text-[10px] text-gray-600">{job.id}</div>
                  </td>
                  <td className="px-4 py-4">
                    <span className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-medium
                      ${job.status === "completed" ? "bg-green-500/10 text-green-400" :
                        job.status === "failed" ? "bg-red-500/10 text-red-400" :
                        job.status === "running" ? "bg-blue-500/10 text-blue-400" :
                        job.status === "canceled" ? "bg-gray-500/10 text-gray-400" :
                        "bg-yellow-500/10 text-yellow-400"}`}>
                      {job.status.toUpperCase()}
                    </span>
                    {job.errorMessage && (
                      <div className="mt-1 max-w-[200px] truncate text-[10px] text-red-400" title={job.errorMessage}>
                        {job.errorMessage}
                      </div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-xs">
                    <div>Created: {new Date(job.createdAt).toLocaleTimeString()}</div>
                    {job.finishedAt && (
                      <div className="text-gray-500">Finished: {new Date(job.finishedAt).toLocaleTimeString()}</div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 text-blue-500 hover:text-blue-400"
                        onClick={(): void => setSelectedJob(job)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      {(job.status === "pending" || job.status === "running") && (
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-8 w-8 text-yellow-500 hover:text-yellow-400"
                          onClick={(): void => { void cancelJob(job.id); }}
                          disabled={actionMutation.isPending && actionMutation.variables?.jobId === job.id}
                        >
                          {actionMutation.isPending && actionMutation.variables?.jobId === job.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
                        </Button>
                      )}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 text-red-500 hover:text-red-400"
                        onClick={(): void => { void deleteJob(job.id); }}
                        disabled={deleteMutation.isPending && deleteMutation.variables === job.id}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </td>
                </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </>
  );

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
        title={title}
        description={description}
        className="mb-6"
      />

      {showTabs ? (
        <Tabs defaultValue={defaultTab} className="space-y-6">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="ai">AI Jobs</TabsTrigger>
            <TabsTrigger value="import">Import Jobs</TabsTrigger>
            <TabsTrigger value="export">Export Jobs</TabsTrigger>
          </TabsList>

          <TabsContent value="ai" className="space-y-4">
            {aiContent}
          </TabsContent>

          <TabsContent value="import" className="space-y-4">
            <SectionPanel className="p-6">
              <h2 className="text-2xl font-bold text-white">Import Jobs</h2>
              <p className="mt-2 text-sm text-gray-400">
                Import jobs will appear here once import tracking is enabled.
              </p>
              <div className="mt-4">
                <Link href="/admin/integrations/imports" className="text-sm text-blue-400 underline">
                  Go to Imports
                </Link>
              </div>
            </SectionPanel>
          </TabsContent>

          <TabsContent value="export">
            <ProductListingJobsPanel showBackToProducts={false} />
          </TabsContent>
        </Tabs>
      ) : (
        <div className="space-y-4">
          {aiContent}
        </div>
      )}

      {selectedJob && (
        <AppModal
          open={true}
          onOpenChange={(open: boolean): void => { if (!open) setSelectedJob(null); }}
          title="Job Details"
        >
          <ModalShell title="Job Details" onClose={(): void => setSelectedJob(null)} size="xl">
            <div className="space-y-6 text-sm">
              <div className="grid grid-cols-2 gap-4 rounded-md bg-gray-900 p-4">
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Status</div>
                  <div className="text-white font-medium">{selectedJob.status.toUpperCase()}</div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Type</div>
                  <div className="text-white font-medium">{selectedJob.type}</div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Entity</div>
                  <div className="text-white font-medium">
                    {getJobMeta(selectedJob).displayEntity}
                  </div>
                </div>
                <div>
                  <div className="text-gray-500 uppercase text-[10px] font-bold">Job ID</div>
                  <div className="text-white font-mono text-xs">{selectedJob.id}</div>
                </div>
              </div>

                <div className="rounded-md border border-border bg-card/40 p-4">
                  <div className="text-gray-400 font-bold text-xs uppercase mb-3">
                    Run Metadata
                  </div>
                  {((): React.ReactNode => {
                    const meta = getJobMeta(selectedJob);
                    const payload = (meta.payload ?? {}) as any;
                    const modelId = payload.modelId;
                    const temperature = payload.temperature;
                    const maxTokens = payload.maxTokens;
                    const vision = payload.vision;
                    const imageUrls = payload.imageUrls;
                    return (
                      <div className="grid grid-cols-1 gap-3 text-xs md:grid-cols-2">
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Source
                          </div>
                          <div className="text-white">
                            {meta.source ?? "unknown"}
                          </div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Entity
                          </div>
                          <div className="text-white">
                            {meta.entityType ?? "unknown"} · {meta.entityId ?? "n/a"}
                          </div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Path
                          </div>
                          <div className="text-white">
                            {meta.pathName ?? meta.pathId ?? "n/a"}
                          </div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Node
                          </div>
                          <div className="text-white">
                            {meta.nodeTitle ?? "n/a"}
                          </div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Model
                          </div>
                          <div className="text-white font-mono">{modelId ?? "n/a"}</div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Tokens / Temp
                          </div>
                          <div className="text-white">
                            {maxTokens ?? "n/a"} / {temperature ?? "n/a"}
                          </div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Vision
                          </div>
                          <div className="text-white">{vision ? "Yes" : "No"}</div>
                        </div>
                        <div>
                          <div className="text-[10px] uppercase text-gray-500 font-bold">
                            Images
                          </div>
                          <div className="text-white">
                            {Array.isArray(imageUrls) ? imageUrls.length : 0}
                          </div>
                        </div>
                      </div>
                    );
                  })()}
                </div>

                {selectedJob.result && (selectedJob.result.visionModel || selectedJob.result.generationModel) && (
                  <div className="rounded-md bg-card/50 border border-border p-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-3">AI Models Used</div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {selectedJob.result.visionModel && (
                        <div>
                          <div className="text-blue-400 text-[10px] font-bold uppercase mb-1">Vision Model (Path 1)</div>
                          <div className="text-white font-mono text-sm">{selectedJob.result.visionModel}</div>
                          {selectedJob.result.visionOutputEnabled !== undefined && (
                            <div className="text-gray-500 text-[10px] mt-1">
                              Refinement: {selectedJob.result.visionOutputEnabled ? "Enabled" : "Disabled"}
                            </div>
                          )}
                        </div>
                      )}
                      {selectedJob.result.generationModel && (
                        <div>
                          <div className="text-purple-400 text-[10px] font-bold uppercase mb-1">Generation Model (Path 2)</div>
                          <div className="text-white font-mono text-sm">{selectedJob.result.generationModel}</div>
                          {selectedJob.result.generationOutputEnabled !== undefined && (
                            <div className="text-gray-500 text-[10px] mt-1">
                              Refinement: {selectedJob.result.generationOutputEnabled ? "Enabled" : "Disabled"}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                )}

                {selectedJob.errorMessage && (
                  <div className="rounded-md border border-red-900/50 bg-red-950/20 p-4">
                    <div className="text-red-400 font-bold text-[10px] uppercase mb-1">Error Message</div>
                    <div className="text-red-200">{selectedJob.errorMessage}</div>
                  </div>
                )}

                {selectedJob.type === "graph_model" && (
                  <div className="rounded-md border border-border bg-card/40 p-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-3">
                      Graph Model Inputs
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-[10px] uppercase text-gray-500 font-bold">Model</div>
                        <div className="text-white text-sm font-mono">
                          {(selectedJob.payload as { modelId?: string } | null)?.modelId ||
                            "Unknown"}
                        </div>
                        <div className="text-[10px] uppercase text-gray-500 font-bold mt-2">
                          Vision Enabled
                        </div>
                        <div className="text-white text-sm">
                          {(selectedJob.payload as { vision?: boolean } | null)?.vision
                            ? "Yes"
                            : "No"}
                        </div>
                      </div>
                      <div className="space-y-2">
                        <div className="text-[10px] uppercase text-gray-500 font-bold">Image URLs</div>
                        {Array.isArray(
                          (selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls
                        ) &&
                        (selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls
                          ?.length ? (
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                            {(selectedJob.payload as { imageUrls?: string[] } | null)?.imageUrls?.map(
                              (url: string, index: number) => (
                                <div key={`${url}-${index}`} className="truncate">
                                  {url}
                                </div>
                              )
                            )}
                          </div>
                        ) : (
                          <div className="text-[11px] text-gray-500">No image URLs in payload.</div>
                        )}
                      </div>
                    </div>
                    <div className="mt-4 space-y-2">
                      <div className="text-[10px] uppercase text-gray-500 font-bold">Prompt</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border whitespace-pre-wrap">
                        {(selectedJob.payload as { prompt?: string } | null)?.prompt ||
                          "No prompt provided."}
                      </pre>
                    </div>
                  </div>
                )}

                {selectedJob.result && typeof selectedJob.result === 'object' && 'analysisInitial' in (selectedJob.result as object) ? (
                  <div className="space-y-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-2">AI Processing Results</div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-blue-400 uppercase text-[10px] font-bold">Path 1: Image Analysis (Initial)</div>
                        <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                          {(selectedJob.result as any).analysisInitial || (selectedJob.result as any).analysis || 'N/A'}
                        </div>
                      </div>

                      {(selectedJob.result as any).analysisFinal && (
                        <div className="space-y-2">
                          <div className="text-blue-400 uppercase text-[10px] font-bold">Path 1: Image Analysis (Final)</div>
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto">
                            {(selectedJob.result as any).analysisFinal}
                          </div>
                        </div>
                      )}
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="text-purple-400 uppercase text-[10px] font-bold">Path 2: Description (Initial)</div>
                        <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto whitespace-pre-wrap">
                          {(selectedJob.result as any).descriptionInitial || (selectedJob.result as any).description || 'N/A'}
                        </div>
                      </div>

                      {(selectedJob.result as any).descriptionFinal && (
                        <div className="space-y-2">
                          <div className="text-purple-400 uppercase text-[10px] font-bold">Path 2: Description (Final)</div>
                          <div className="rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border max-h-40 overflow-auto whitespace-pre-wrap">
                            {(selectedJob.result as any).descriptionFinal}
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                ) : selectedJob.result && typeof selectedJob.result === 'object' && 'translations' in (selectedJob.result as object) ? (
                  <div className="space-y-4">
                    <div className="text-gray-400 font-bold text-xs uppercase mb-2">Translation Results</div>

                    {(selectedJob.result as any).translationModel && (
                      <div className="rounded-md bg-card/50 border border-border p-4 mb-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          <div>
                            <div className="text-green-400 text-[10px] font-bold uppercase mb-1">Translation Model</div>
                            <div className="text-white font-mono text-sm">{(selectedJob.result as any).translationModel}</div>
                          </div>
                          {(selectedJob.result as any).sourceLanguage && (
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Source Language</div>
                              <div className="text-white text-sm">{(selectedJob.result as any).sourceLanguage}</div>
                            </div>
                          )}
                          {(selectedJob.result as any).targetLanguages && (
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Target Languages</div>
                              <div className="text-white text-sm">{(selectedJob.result as any).targetLanguages.join(', ')}</div>
                            </div>
                          )}
                        </div>
                      </div>
                    )}

                    <div className="space-y-4">
                      {(selectedJob.result as any).translations && Object.entries((selectedJob.result as any).translations).map(([lang, trans]: [string, any]) => (
                        <div key={lang} className="rounded-md border border-border bg-card/30 p-4">
                          <div className="text-green-400 uppercase text-[10px] font-bold mb-3">{lang}</div>
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Translated Name</div>
                              <div className="text-white text-sm p-2 bg-gray-900 rounded border border-border">
                                {trans.name || 'N/A'}
                              </div>
                            </div>
                            <div>
                              <div className="text-gray-500 text-[10px] font-bold uppercase mb-1">Translated Description</div>
                              <div className="text-white text-sm p-2 bg-gray-900 rounded border border-border max-h-32 overflow-auto whitespace-pre-wrap">
                                {trans.description || 'N/A'}
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="space-y-2">
                      <div className="text-gray-500 uppercase text-[10px] font-bold">Payload (Input Config)</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-400 border border-border">
                        {JSON.stringify(selectedJob.payload, null, 2)}
                      </pre>
                    </div>
                    <div className="space-y-2">
                      <div className="text-gray-500 uppercase text-[10px] font-bold">Result (Output)</div>
                      <pre className="max-h-60 overflow-auto rounded-md bg-gray-900 p-3 text-[11px] text-gray-300 border border-border whitespace-pre-wrap">
                        {selectedJob.result ? JSON.stringify(selectedJob.result, null, 2) : "No result yet."}
                      </pre>
                    </div>
                  </div>
                )}

                <div className="text-[10px] text-gray-600">
                  Created: {new Date(selectedJob.createdAt).toLocaleString()} 
                  {selectedJob.startedAt && ` | Started: ${new Date(selectedJob.startedAt).toLocaleString()}`}
                  {selectedJob.finishedAt && ` | Finished: ${new Date(selectedJob.finishedAt).toLocaleString()}`}
                </div>
              </div>
          </ModalShell>
        </AppModal>
      )}
    </div>
  );
}

