// --- Composite Hook ---

export function useNoteData({
  selectedNotebookId,
  selectedFolderId,
  searchQuery,
  searchScope,
  filterPinned,
  filterArchived,
  filterFavorite,
  filterTagIds,
  setSelectedNotebookId,
}: UseNoteDataProps) {
  const queryClient = useQueryClient();
  const notesRef = useRef<NoteWithRelations[]>([]);
  const folderTreeRef = useRef<CategoryWithChildren[]>([]);

  // Queries
  const notesQuery = useNotes({
    search: searchQuery,
    searchScope,
    isPinned: filterPinned,
    isArchived: filterArchived,
    isFavorite: filterFavorite,
    tagIds: filterTagIds,
    categoryIds: selectedFolderId ? [selectedFolderId] : [],
    notebookId: selectedNotebookId,
    truncateContent: true,
  });

  const notebooksQuery = useNoteTree();
  const tagsQuery = useNoteTags();
  const themesQuery = useNoteThemes();
  const categoriesQuery = useNoteCategories();

  // Derived state
  const notes = notesQuery.data || [];
  const notebooks = notebooksQuery.data || [];
  const tags = tagsQuery.data || [];
  const themes = themesQuery.data || [];
  const categories = categoriesQuery.data || [];

  const notebook = useMemo(
    () => notebooks.find((n) => n.id === selectedNotebookId) || null,
    [notebooks, selectedNotebookId]
  );

  // Sync refs for imperative access
  useEffect(() => {
    notesRef.current = notes;
  }, [notes]);

  // Build folder tree
  const folderTree = useMemo(() => {
    if (!categories.length) {
      folderTreeRef.current = [];
      return [];
    }

    const categoryMap = new Map<string, CategoryWithChildren>();

    // Initialize map
    categories.forEach((cat) => {
      if (selectedNotebookId && cat.notebookId !== selectedNotebookId) return;
      categoryMap.set(cat.id, {
        ...cat,
        children: [],
        notes: [],
        _count: { notes: 0 },
      });
    });

    const roots: CategoryWithChildren[] = [];

    // Build tree
    categoryMap.forEach((node) => {
      if (node.parentId && categoryMap.has(node.parentId)) {
        categoryMap.get(node.parentId)!.children.push(node);
      } else {
        roots.push(node);
      }
    });

    // Sort by sortIndex or name
    const sortNodes = (nodes: CategoryWithChildren[]) => {
      nodes.sort((a, b) => {
        if (a.sortIndex !== null && b.sortIndex !== null) {
          return (a.sortIndex ?? 0) - (b.sortIndex ?? 0);
        }
        return a.name.localeCompare(b.name);
      });
      nodes.forEach((node) => sortNodes(node.children));
    };

    sortNodes(roots);
    folderTreeRef.current = roots;
    return roots;
  }, [categories, selectedNotebookId]);

  // Setters (wrappers for query updates or optimistic UI - simplified for now)
  const setNotes = useCallback((updater: NoteWithRelations[] | ((prev: NoteWithRelations[] | undefined) => NoteWithRelations[])) => {
    queryClient.setQueryData(["notes", {
        search: searchQuery,
        searchScope,
        isPinned: filterPinned,
        isArchived: filterArchived,
        isFavorite: filterFavorite,
        tagIds: filterTagIds,
        categoryIds: selectedFolderId ? [selectedFolderId] : [],
        notebookId: selectedNotebookId,
        truncateContent: true,
      }], updater);
  }, [queryClient, searchQuery, searchScope, filterPinned, filterArchived, filterFavorite, filterTagIds, selectedFolderId, selectedNotebookId]);

  const setNotebook = useCallback((newNotebook: NotebookRecord) => {
    // This might need to update the notebook in the list
    queryClient.setQueryData(["notes", "notebooks"], (old: NotebookRecord[] | undefined) => {
      if (!old) return [newNotebook];
      return old.map(n => n.id === newNotebook.id ? newNotebook : n);
    });
    // And possibly selected notebook state if needed, but that's passed in
  }, [queryClient]);

  // Initial selection
  useEffect(() => {
    if (!selectedNotebookId && notebooks.length > 0) {
      setSelectedNotebookId(notebooks[0]!.id);
    }
  }, [selectedNotebookId, notebooks, setSelectedNotebookId]);

  return {
    notes,
    setNotes,
    tags,
    themes,
    notebook,
    setNotebook,
    folderTree,
    loading: notesQuery.isLoading || notebooksQuery.isLoading,
    notesRef,
    folderTreeRef,
    fetchNotes: async () => { await notesQuery.refetch(); },
    fetchFolderTree: async () => { await categoriesQuery.refetch(); },
    fetchTags: async () => { await tagsQuery.refetch(); },
  };
}

import { useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import type { NoteWithRelations, CategoryWithChildren } from "@/shared/types/notes";
import type { UseNoteOperationsProps } from "@/features/notesapp/types/notes-hooks";
import { findFolderParentId, findFolderById } from "@/features/foldertree";
import type { UndoAction } from "@/features/notesapp/types/notes-hooks";
import {
  useCreateCategoryMutation,
  useDeleteCategoryMutation,
  useUpdateCategoryMutation,
  useCreateNoteMutation,
  useDeleteNoteMutation,
  useUpdateNoteMutation,
} from "./useNoteData";

export function useNoteOperations({
  selectedNotebookId,
  notesRef,
  folderTreeRef,
  setUndoStack,
  toast,
  setSelectedFolderId,
  setSelectedNote,
  selectedNote,
}: UseNoteOperationsProps): {
  handleCreateFolder: (parentId?: string | null) => Promise<void>;
  handleDeleteFolder: (folderId: string) => Promise<void>;
  handleRenameFolder: (folderId: string, newName: string) => Promise<void>;
  handleDuplicateNote: (noteId: string) => Promise<void>;
  handleDeleteNoteFromTree: (noteId: string) => Promise<void>;
  handleRenameNote: (noteId: string, newTitle: string) => Promise<void>;
  handleMoveNoteToFolder: (noteId: string, folderId: string | null) => Promise<void>;
  handleMoveFolderToFolder: (folderId: string, targetParentId: string | null) => Promise<void>;
  handleReorderFolder: (folderId: string, targetId: string, position: "before" | "after") => Promise<void>;
  handleRelateNotes: (sourceNoteId: string, targetNoteId: string) => Promise<void>;
} {
  const queryClient = useQueryClient();
  const createCategoryMutation = useCreateCategoryMutation();
  const deleteCategoryMutation = useDeleteCategoryMutation();
  const updateCategoryMutation = useUpdateCategoryMutation();
  const createNoteMutation = useCreateNoteMutation();
  const deleteNoteMutation = useDeleteNoteMutation();
  const updateNoteMutation = useUpdateNoteMutation();

  const handleCreateFolder = useCallback(async (parentId?: string | null): Promise<void> => {
    const folderName = prompt("Enter folder name:");
    if (!folderName) return;

    try {
      if (!selectedNotebookId) return;
      const created = await createCategoryMutation.mutateAsync({
        name: folderName,
        parentId: parentId ?? null,
        notebookId: selectedNotebookId,
      });

      if (created?.id) {
        setSelectedFolderId(created.id);
      }
      toast("Folder created successfully");
    } catch (error: unknown) {
      console.error("Failed to create folder:", error);
      toast("An unexpected error occurred while creating the folder", { variant: "error" });
    }
  }, [selectedNotebookId, createCategoryMutation, setSelectedFolderId, toast]);

  const handleDeleteFolder = useCallback(async (folderId: string): Promise<void> => {
    if (!confirm("Delete this folder and all its contents (subfolders, notes, and attachments)? This action cannot be undone.")) return;

    try {
      await deleteCategoryMutation.mutateAsync(folderId);
      toast("Folder deleted successfully");
    } catch (error: unknown) {
      console.error("Failed to delete folder:", error);
      toast("An unexpected error occurred while deleting the folder", { variant: "error" });
    }
  }, [deleteCategoryMutation, toast]);

  const handleRenameFolder = useCallback(async (folderId: string, newName: string): Promise<void> => {
    const currentFolder = findFolderById(folderTreeRef.current, folderId);
    const previousName = currentFolder?.name ?? "";
    try {
      await updateCategoryMutation.mutateAsync({ id: folderId, name: newName });

      if (previousName && previousName !== newName) {
        setUndoStack((prev: UndoAction[]) => [
          { type: "renameFolder", folderId, fromName: previousName, toName: newName },
          ...prev,
        ]);
      }
      toast("Folder renamed successfully");
    } catch (error: unknown) {
      console.error("Failed to rename folder:", error);
      toast("An unexpected error occurred while renaming the folder", { variant: "error" });
    }
  }, [folderTreeRef, updateCategoryMutation, setUndoStack, toast]);

  const handleDuplicateNote = useCallback(async (noteId: string): Promise<void> => {
    try {
      const note = await queryClient.fetchQuery<NoteWithRelations>({
        queryKey: ["notes", noteId],
        queryFn: async () => {
          const response = await fetch(`/api/notes/${noteId}`, { cache: "no-store" });
          if (!response.ok) throw new Error("Failed to fetch note");
          return response.json();
        }
      });

      const baseTitle = note.title.replace(/\s*\(\d+\)$/, "");
      let newTitle = `${baseTitle} (1)`;

      const existingNotes = notesRef.current.filter((n: NoteWithRelations) =>
        n.title.startsWith(baseTitle) && n.title !== note.title
      );
      if (existingNotes.length > 0) {
        const numbers = existingNotes
          .map((n: NoteWithRelations) => {
            const match = n.title.match(/\((\d+)\)$/);
            return match ? parseInt(match[1]!, 10) : 0;
          })
          .filter((n: number) => n > 0);
        const maxNumber = Math.max(0, ...numbers);
        newTitle = `${baseTitle} (${maxNumber + 1})`;
      }

      await createNoteMutation.mutateAsync({
        title: newTitle,
        content: note.content,
        color: note.color,
        isPinned: note.isPinned,
        isArchived: note.isArchived,
        isFavorite: note.isFavorite,
        tagIds: note.tags.map((t: { tagId: string }) => t.tagId),
        categoryIds: note.categories.map((c: { categoryId: string }) => c.categoryId),
        notebookId: note.notebookId ?? selectedNotebookId ?? null,
      });

      toast("Note duplicated successfully");
    } catch (error: unknown) {
      console.error("Failed to duplicate note:", error);
      toast("An unexpected error occurred while duplicating the note", { variant: "error" });
    }
  }, [selectedNotebookId, notesRef, createNoteMutation, toast, queryClient]);

  const handleDeleteNoteFromTree = useCallback(async (noteId: string): Promise<void> => {
    if (!confirm("Are you sure you want to delete this note?")) return;

    try {
      await deleteNoteMutation.mutateAsync(noteId);
      if (selectedNote?.id === noteId) {
        setSelectedNote(null);
      }
      toast("Note deleted successfully");
    } catch (error: unknown) {
      console.error("Failed to delete note:", error);
      toast("An unexpected error occurred while deleting the note", { variant: "error" });
    }
  }, [deleteNoteMutation, selectedNote, setSelectedNote, toast]);

  const handleRenameNote = useCallback(async (noteId: string, newTitle: string): Promise<void> => {
    const currentNote = notesRef.current.find((note: NoteWithRelations) => note.id === noteId);
    const previousTitle = currentNote?.title ?? "";
    try {
      const updatedNote = await updateNoteMutation.mutateAsync({ id: noteId, title: newTitle });

      if (previousTitle && previousTitle !== newTitle) {
        setUndoStack((prev: UndoAction[]) => [
          { type: "renameNote", noteId, fromTitle: previousTitle, toTitle: newTitle },
          ...prev,
        ]);
      }

      if (selectedNote?.id === noteId) {
        setSelectedNote(updatedNote as NoteWithRelations);
      }
      toast("Note renamed successfully");
    } catch (error: unknown) {
      console.error("Failed to rename note:", error);
      toast("An unexpected error occurred while renaming the note", { variant: "error" });
    }
  }, [notesRef, updateNoteMutation, setUndoStack, selectedNote, setSelectedNote, toast]);

  const handleMoveNoteToFolder = useCallback(async (noteId: string, folderId: string | null): Promise<void> => {
    const currentNote = notesRef.current.find((note: NoteWithRelations) => note.id === noteId);
    const previousFolderId = currentNote?.categories?.[0]?.categoryId ?? null;
    try {
      await updateNoteMutation.mutateAsync({
        id: noteId,
        categoryIds: folderId ? [folderId] : [],
      });

      if (previousFolderId !== folderId) {
        setUndoStack((prev: UndoAction[]) => [
          { type: "moveNote", noteId, fromFolderId: previousFolderId, toFolderId: folderId },
          ...prev,
        ]);
      }
      toast("Note moved successfully");
    } catch (error: unknown) {
      console.error("Failed to move note:", error);
      toast("An unexpected error occurred while moving the note", { variant: "error" });
    }
  }, [notesRef, updateNoteMutation, setUndoStack, toast]);

  const handleMoveFolderToFolder = useCallback(async (folderId: string, targetParentId: string | null): Promise<void> => {
    const previousParentId = findFolderParentId(folderTreeRef.current, folderId);
    try {
      await updateCategoryMutation.mutateAsync({
        id: folderId,
        parentId: targetParentId,
      });

      if (previousParentId !== targetParentId) {
        setUndoStack((prev: UndoAction[]) => [
          { type: "moveFolder", folderId, fromParentId: previousParentId, toParentId: targetParentId },
          ...prev,
        ]);
      }
      toast("Folder moved successfully");
    } catch (error: unknown) {
      console.error("Failed to move folder:", error);
      toast("An unexpected error occurred while moving the folder", { variant: "error" });
    }
  }, [folderTreeRef, updateCategoryMutation, setUndoStack, toast]);

  const handleReorderFolder = useCallback(async (folderId: string, targetId: string, position: "before" | "after"): Promise<void> => {
    const tree = folderTreeRef.current;
    const draggedFolder = findFolderById(tree, folderId);
    if (!draggedFolder) return;

    const targetParentId = findFolderParentId(tree, targetId);
    const draggedParentId = findFolderParentId(tree, folderId);

    const getSiblings = (parentId: string | null): CategoryWithChildren[] => {
      if (!parentId) return tree;
      const parent = findFolderById(tree, parentId);
      return parent?.children ?? [];
    };

    const siblings = getSiblings(targetParentId);
    const filtered = siblings.filter((sibling: CategoryWithChildren) => sibling.id !== folderId);
    const targetIndex = filtered.findIndex((sibling: CategoryWithChildren) => sibling.id === targetId);
    if (targetIndex === -1) return;

    const insertIndex = position === "before" ? targetIndex : targetIndex + 1;
    filtered.splice(insertIndex, 0, draggedFolder);

    try {
      await Promise.all(
        filtered.map((sibling: CategoryWithChildren, index: number) => {
          const update: Record<string, unknown> = { sortIndex: index };
          if (sibling.id === folderId && draggedParentId !== targetParentId) {
            update.parentId = targetParentId;
          }
          // Using mutation for each update
          return updateCategoryMutation.mutateAsync({
            id: sibling.id,
            sortIndex: index,
            ...(sibling.id === folderId && draggedParentId !== targetParentId ? { parentId: targetParentId } : {})
          });
        })
      );
      toast("Folder reordered successfully");
    } catch (error: unknown) {
      console.error("Failed to reorder folder:", error);
      toast("Failed to reorder folder", { variant: "error" });
    }
  }, [folderTreeRef, updateCategoryMutation, toast]);

  const handleRelateNotes = useCallback(async (sourceNoteId: string, targetNoteId: string): Promise<void> => {
    if (!sourceNoteId || !targetNoteId) return;
    if (sourceNoteId === targetNoteId) return;
    try {
      const [sourceNote, targetNote] = await Promise.all([
        queryClient.fetchQuery<NoteWithRelations>({
          queryKey: ["notes", sourceNoteId],
          queryFn: async () => {
            const res = await fetch(`/api/notes/${sourceNoteId}`, { cache: "no-store" });
            if (!res.ok) throw new Error("Failed to fetch source note");
            return res.json();
          }
        }),
        queryClient.fetchQuery<NoteWithRelations>({
          queryKey: ["notes", targetNoteId],
          queryFn: async () => {
            const res = await fetch(`/api/notes/${targetNoteId}`, { cache: "no-store" });
            if (!res.ok) throw new Error("Failed to fetch target note");
            return res.json();
          }
        }),
      ]);

      const sourceRelatedIds =
        sourceNote.relationsFrom?.map((rel: { targetNote: { id: string } }) => rel.targetNote.id) || [];
      const alreadyLinked = sourceRelatedIds.includes(targetNoteId);
      if (alreadyLinked) {
        toast("Notes are already linked", { variant: "info" });
        return;
      }

      const nextSourceIds = Array.from(new Set([...sourceRelatedIds, targetNoteId]));

      const targetRelatedIds =
        targetNote.relationsFrom?.map((rel: { targetNote: { id: string } }) => rel.targetNote.id) || [];
      const nextTargetIds = Array.from(new Set([...targetRelatedIds, sourceNoteId]));

      await Promise.all([
        updateNoteMutation.mutateAsync({ id: sourceNoteId, relatedNoteIds: nextSourceIds }),
        updateNoteMutation.mutateAsync({ id: targetNoteId, relatedNoteIds: nextTargetIds }),
      ]);

      toast("Notes linked");
    } catch (error: unknown) {
      console.error("Failed to relate notes:", error);
      toast("Failed to link notes", { variant: "error" });
    }
  }, [updateNoteMutation, toast, queryClient]);

  return {
    handleCreateFolder,
    handleDeleteFolder,
    handleRenameFolder,
    handleDuplicateNote,
    handleDeleteNoteFromTree,
    handleRenameNote,
    handleMoveNoteToFolder,
    handleMoveFolderToFolder,
    handleReorderFolder,
    handleRelateNotes,
  };
}

"use client";

import { useMutation, useQueryClient, type UseMutationResult } from "@tanstack/react-query";
import { logKeys } from "./useLogQueries";

export function useClearLogsMutation(): UseMutationResult<boolean, Error, void> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/system/logs", { method: "DELETE" });
      if (!res.ok) throw new Error("Failed to clear logs.");
      return true;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: logKeys.all });
    },
  });
}

export function useRebuildIndexesMutation(): UseMutationResult<any, Error, void> {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async () => {
      const res = await fetch("/api/system/diagnostics/mongo-indexes", {
        method: "POST",
      });
      if (!res.ok) throw new Error("Failed to rebuild Mongo indexes.");
      return res.json();
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: logKeys.diagnostics });
    },
  });
}

"use client";

import { useQuery, type UseQueryResult } from "@tanstack/react-query";
import type { SystemLogMetrics, SystemLogRecord } from "@/shared/types/system-logs";

export type LogFilters = {
  page?: number;
  pageSize?: number;
  level?: string;
  query?: string;
  source?: string;
  from?: string | null;
  to?: string | null;
};

export const logKeys = {
  all: ["system-logs"] as const,
  list: (filters: LogFilters) => ["system-logs", "list", filters] as const,
  metrics: (filters: Omit<LogFilters, "page" | "pageSize">) => ["system-logs", "metrics", filters] as const,
  diagnostics: ["mongo-index-diagnostics"] as const,
};

export function useSystemLogs(filters: LogFilters): UseQueryResult<{
  logs?: SystemLogRecord[];
  total?: number;
  page?: number;
  pageSize?: number;
}, Error> {
  return useQuery({
    queryKey: logKeys.list(filters),
    queryFn: async () => {
      const params = new URLSearchParams();
      if (filters.page) params.set("page", String(filters.page));
      if (filters.pageSize) params.set("pageSize", String(filters.pageSize));
      if (filters.level && filters.level !== "all") params.set("level", filters.level);
      if (filters.query?.trim()) params.set("query", filters.query.trim());
      if (filters.source?.trim()) params.set("source", filters.source.trim());
      if (filters.from) params.set("from", filters.from);
      if (filters.to) params.set("to", filters.to);

      const res = await fetch(`/api/system/logs?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load system logs.");
      return res.json();
    },
  });
}

export function useSystemLogMetrics(filters: Omit<LogFilters, "page" | "pageSize">): UseQueryResult<{ metrics?: SystemLogMetrics }, Error> {
  return useQuery({
    queryKey: logKeys.metrics(filters),
    queryFn: async () => {
      const params = new URLSearchParams();
      if (filters.level && filters.level !== "all") params.set("level", filters.level);
      if (filters.query?.trim()) params.set("query", filters.query.trim());
      if (filters.source?.trim()) params.set("source", filters.source.trim());
      if (filters.from) params.set("from", filters.from);
      if (filters.to) params.set("to", filters.to);

      const res = await fetch(`/api/system/logs/metrics?${params.toString()}`);
      if (!res.ok) throw new Error("Failed to load system log metrics.");
      return res.json();
    },
  });
}

export function useMongoDiagnostics(): UseQueryResult<any, Error> {
  return useQuery({
    queryKey: logKeys.diagnostics,
    queryFn: async () => {
      const res = await fetch("/api/system/diagnostics/mongo-indexes");
      if (!res.ok) throw new Error("Failed to load Mongo index diagnostics.");
      return res.json();
    },
  });
}

"use client";

import { Button, Input, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, useToast, Label, ListPanel, SectionHeader, SectionPanel, Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/shared/ui";
import { useEffect, useMemo, useState, type ChangeEvent } from "react";
import { useSearchParams } from "next/navigation";
import { useSystemLogs, useSystemLogMetrics, useMongoDiagnostics } from "@/features/observability/hooks/useLogQueries";
import { useClearLogsMutation, useRebuildIndexesMutation } from "@/features/observability/hooks/useLogMutations";

import { RefreshCcw, Trash2, Download } from "lucide-react";
import type { SystemLogMetrics, SystemLogRecord, SystemLogLevel } from "@/shared/types/system-logs";

const levelOptions: Array<{ value: SystemLogLevel | "all"; label: string }> = [
  { value: "all", label: "All levels" },
  { value: "error", label: "Errors" },
  { value: "warn", label: "Warnings" },
  { value: "info", label: "Info" },
];

type MongoIndexInfo = {
  name?: string;
  key: Record<string, unknown>;
};

type MongoCollectionIndexStatus = {
  name: string;
  expected: MongoIndexInfo[];
  existing: MongoIndexInfo[];
  missing: MongoIndexInfo[];
  extra: MongoIndexInfo[];
  error?: string;
};

const formatTimestamp = (value: Date | string): string => {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return "—";
  return date.toLocaleString();
};

const formatDateParam = (value: string, endOfDay: boolean = false): string | null => {
  if (!value) return null;
  const suffix = endOfDay ? "T23:59:59.999" : "T00:00:00.000";
  const date = new Date(`${value}${suffix}`);
  if (Number.isNaN(date.getTime())) return null;
  return date.toISOString();
};

export default function SystemLogsPage(): React.JSX.Element {
  const { toast } = useToast();
  const searchParams = useSearchParams();

  const [level, setLevel] = useState<SystemLogLevel | "all">(() => {
    const p = searchParams?.get("level");
    if (p && levelOptions.some((option: (typeof levelOptions)[number]) => option.value === p)) {
      return p as SystemLogLevel | "all";
    }
    return "all";
  });

  const [query, setQuery] = useState(() => searchParams?.get("query") ?? "");
  const [source, setSource] = useState(() => searchParams?.get("source") ?? "");

  const [fromDate, setFromDate] = useState(() => {
    const p = searchParams?.get("from");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [toDate, setToDate] = useState(() => {
    const p = searchParams?.get("to");
    if (!p) return "";
    const date = new Date(p);
    return Number.isNaN(date.getTime()) ? "" : date.toISOString().slice(0, 10);
  });

  const [page, setPage] = useState(1);
  const pageSize = 50;

  const filters = useMemo(() => ({
    page,
    pageSize,
    level,
    query,
    source,
    from: formatDateParam(fromDate),
    to: formatDateParam(toDate, true),
  }), [page, pageSize, level, query, source, fromDate, toDate]);

  const metricsFilters = useMemo(() => ({
    level,
    query,
    source,
    from: formatDateParam(fromDate),
    to: formatDateParam(toDate, true),
  }), [level, query, source, fromDate, toDate]);

  // Queries
  const logsQuery = useSystemLogs(filters);
  const metricsQuery = useSystemLogMetrics(metricsFilters);
  const mongoDiagnosticsQuery = useMongoDiagnostics();

  // Mutations
  const clearLogsMutation = useClearLogsMutation();
  const rebuildIndexesMutation = useRebuildIndexesMutation();

  useEffect(() => {
    if (logsQuery.error) toast((logsQuery.error).message, { variant: "error" });
  }, [logsQuery.error, toast]);

  useEffect(() => {
    if (metricsQuery.error) toast((metricsQuery.error).message, { variant: "error" });
  }, [metricsQuery.error, toast]);

  useEffect(() => {
    if (mongoDiagnosticsQuery.error) toast((mongoDiagnosticsQuery.error).message, { variant: "error" });
  }, [mongoDiagnosticsQuery.error, toast]);

  const logs = logsQuery.data?.logs ?? [];
  const total = logsQuery.data?.total ?? 0;
  const metrics = metricsQuery.data?.metrics ?? null;
  const diagnostics = mongoDiagnosticsQuery.data?.collections ?? [];
  const diagnosticsUpdatedAt = mongoDiagnosticsQuery.data?.generatedAt ?? null;

  const totalPages: number = useMemo((): number => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const clearLogs = async (): Promise<void> => {
    if (!window.confirm("Clear all system logs?")) return;
    try {
      await clearLogsMutation.mutateAsync();
      toast("System logs cleared.", { variant: "success" });
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to clear logs.", {
        variant: "error",
      });
    }
  };

  const rebuildMongoIndexes = async (): Promise<void> => {
    if (!window.confirm("Rebuild missing Mongo indexes for AI Paths runtime?")) return;
    try {
      const result = await rebuildIndexesMutation.mutateAsync();
      const createdCount = result?.created?.length ?? 0;
      toast(
        createdCount > 0
          ? `Rebuilt ${createdCount} index(es).`
          : "Mongo indexes already up to date.",
        { variant: "success" }
      );
    } catch (error: unknown) {
      toast(error instanceof Error ? error.message : "Failed to rebuild indexes.", {
        variant: "error",
      });
    }
  };

  const exportLogs = async (): Promise<void> => {
    try {
      const payload = JSON.stringify(logs, null, 2);
      await navigator.clipboard.writeText(payload);
      toast("Logs copied to clipboard.", { variant: "success" });
    } catch (_error: unknown) {
      toast("Failed to copy logs.", { variant: "error" });
    }
  };

  const levelStyles: Record<string, string> = {
    error: "border-red-500/40 text-red-300 bg-red-500/10",
    warn: "border-yellow-500/40 text-yellow-300 bg-yellow-500/10",
    info: "border-blue-500/40 text-blue-300 bg-blue-500/10",
  };

  const getContextValue = (context: unknown, path: string): unknown => {
    if (!context || typeof context !== "object") return null;
    return path.split(".").reduce<unknown>((acc: unknown, key: string): unknown => {
      if (!acc || typeof acc !== "object") return null;
      return (acc as Record<string, unknown>)[key] ?? null;
    }, context);
  };

  const levels = metrics?.levels ?? { error: 0, warn: 0, info: 0 };

  return (
    <div className="container mx-auto py-10">
      <ListPanel
        header={
          <SectionHeader
            title="System Logs"
            description="Centralized error and warning events captured across the platform."
            actions={
              <>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => window.location.assign("/admin/settings/logging")}
                >
                  Client Logging Settings
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    void logsQuery.refetch();
                    void metricsQuery.refetch();
                  }}
                  disabled={logsQuery.isFetching || metricsQuery.isFetching}
                >
                  <RefreshCcw className={`mr-2 h-4 w-4 ${(logsQuery.isFetching || metricsQuery.isFetching) ? "animate-spin" : ""}`} />
                  Refresh
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void exportLogs()}
                  disabled={logs.length === 0}
                >
                  <Download className="mr-2 h-4 w-4" />
                  Copy JSON
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void clearLogs()}
                  className="border-red-500/40 text-red-200 hover:bg-red-500/10"
                  disabled={logs.length === 0 || clearLogsMutation.isPending}
                >
                  <Trash2 className="mr-2 h-4 w-4" />
                  {clearLogsMutation.isPending ? "Clearing..." : "Clear Logs"}
                </Button>
              </>
            }
          />
        }
        alerts={
          <SectionPanel className="space-y-4">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <div className="text-lg font-semibold text-white">Diagnostics</div>
                <div className="text-xs text-gray-400">
                  Mongo index status for AI Paths runtime collections.
                </div>
              </div>
              <div className="flex items-center gap-2 text-xs text-gray-500">
                <span>
                  {diagnosticsUpdatedAt
                    ? `Updated ${formatTimestamp(diagnosticsUpdatedAt)}`
                    : "—"}
                </span>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void mongoDiagnosticsQuery.refetch()}
                  disabled={mongoDiagnosticsQuery.isFetching}
                >
                  Refresh
                </Button>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => void rebuildMongoIndexes()}
                  disabled={rebuildIndexesMutation.isPending}
                  className="border-amber-500/40 text-amber-200 hover:bg-amber-500/10"
                >
                  {rebuildIndexesMutation.isPending ? "Rebuilding..." : "Rebuild missing indexes"}
                </Button>
              </div>
            </div>
            {mongoDiagnosticsQuery.isLoading ? (
              <div className="text-sm text-gray-400">Loading diagnostics...</div>
            ) : diagnostics.length === 0 ? (
              <div className="text-sm text-gray-400">No diagnostics available.</div>
            ) : (
              <div className="rounded-md border border-border/70 bg-card/60">
                <Table>
                  <TableHeader>
                    <TableRow className="border-border/60">
                      <TableHead className="text-xs text-gray-400">Collection</TableHead>
                      <TableHead className="text-xs text-gray-400">Expected</TableHead>
                      <TableHead className="text-xs text-gray-400">Missing</TableHead>
                      <TableHead className="text-xs text-gray-400">Extra</TableHead>
                      <TableHead className="text-xs text-gray-400 text-right">Status</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {diagnostics.map((collection: MongoCollectionIndexStatus) => {
                      const missingCount = collection.missing.length;
                      const extraCount = collection.extra.length;
                      const statusLabel = collection.error
                        ? "Error"
                        : missingCount === 0
                          ? "OK"
                          : "Missing";
                      return (
                        <TableRow key={collection.name} className="border-border/50">
                          <TableCell className="font-mono text-xs text-gray-200">
                            {collection.name}
                          </TableCell>
                          <TableCell className="text-xs text-gray-300">
                            {collection.expected.length}
                          </TableCell>
                          <TableCell className="text-xs text-gray-300">
                            {collection.error ? (
                              <div className="space-y-1 text-rose-200">
                                <div>—</div>
                                <div className="rounded bg-rose-500/10 px-2 py-1 text-[10px]">
                                  {collection.error}
                                </div>
                              </div>
                            ) : missingCount === 0 ? (
                              "0"
                            ) : (
                              <div className="space-y-1">
                                <div className="text-amber-200">{missingCount}</div>
                                <div className="space-y-1 text-[10px] text-amber-200">
                                  {collection.missing.map((item: MongoIndexInfo) => (
                                    <div
                                      key={JSON.stringify(item.key)}
                                      className="rounded bg-amber-500/10 px-2 py-1"
                                    >
                                      {JSON.stringify(item.key)}
                                    </div>
                                  ))}
                                </div>
                              </div>
                            )}
                          </TableCell>
                          <TableCell className="text-xs text-gray-300">
                            {extraCount}
                          </TableCell>
                          <TableCell className="text-right">
                            <span
                              className={`rounded border px-2 py-0.5 text-xs ${
                                collection.error
                                  ? "border-rose-400/40 text-rose-200 bg-rose-500/10"
                                  : missingCount === 0
                                  ? "border-emerald-400/40 text-emerald-200 bg-emerald-500/10"
                                  : "border-amber-400/40 text-amber-200 bg-amber-500/10"
                              }`}
                            >
                              {statusLabel}
                            </span>
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </div>
            )}
          </SectionPanel>
        }
        filters={
          <SectionPanel>
            <div className="grid gap-4 md:grid-cols-4">
              <div>
                <Label className="text-xs text-gray-400">Level</Label>
                <Select
                  value={level}
                  onValueChange={(value: string): void => {
                    setLevel(value as SystemLogLevel | "all");
                    setPage(1);
                  }}
                >
                  <SelectTrigger className="mt-2">
                    <SelectValue placeholder="All levels" />
                  </SelectTrigger>
                  <SelectContent>
                    {levelOptions.map((option: (typeof levelOptions)[number]) => (
                      <SelectItem key={option.value} value={option.value}>
                        {option.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div>
                <Label className="text-xs text-gray-400">Search</Label>
                <Input
                  className="mt-2"
                  placeholder="Message or source"
                  value={query}
                  onChange={(event: ChangeEvent<HTMLInputElement>): void => {
                    setQuery(event.target.value);
                    setPage(1);
                  }}
                />
              </div>
              <div>
                <Label className="text-xs text-gray-400">Source</Label>
                <Input
                  className="mt-2"
                  placeholder="api/products, auth, etc."
                  value={source}
                  onChange={(event: ChangeEvent<HTMLInputElement>): void => {
                    setSource(event.target.value);
                    setPage(1);
                  }}
                />
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div>
                  <Label className="text-xs text-gray-400">From</Label>
                  <Input
                    className="mt-2"
                    type="date"
                    value={fromDate}
                    onChange={(event: ChangeEvent<HTMLInputElement>): void => {
                      setFromDate(event.target.value);
                      setPage(1);
                    }}
                  />
                </div>
                <div>
                  <Label className="text-xs text-gray-400">To</Label>
                  <Input
                    className="mt-2"
                    type="date"
                    value={toDate}
                    onChange={(event: ChangeEvent<HTMLInputElement>): void => {
                      setToDate(event.target.value);
                      setPage(1);
                    }}
                  />
                </div>
              </div>
            </div>
          </SectionPanel>
        }
      >
        <div className="space-y-6">
          <div className="rounded-md border border-border bg-card/60 p-4">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <div>
                <h2 className="text-lg font-semibold text-white">Metrics</h2>
                <p className="text-xs text-gray-400">
                  Metrics reflect the current filters.
                </p>
              </div>
              <div className="text-xs text-gray-500">
                {metrics?.generatedAt ? `Updated ${formatTimestamp(metrics.generatedAt)}` : "—"}
              </div>
            </div>
            {metricsQuery.isLoading ? (
              <div className="mt-4 text-sm text-gray-400">Loading metrics...</div>
            ) : !metrics ? (
              <div className="mt-4 text-sm text-gray-400">
                No metrics available yet.
              </div>
            ) : (
              <div className="mt-4 grid gap-4 md:grid-cols-3">
                <div className="rounded-md border border-border bg-card p-3">
                  <div className="text-xs text-gray-400">Totals</div>
                  <div className="mt-2 space-y-1 text-sm text-gray-200">
                    <div>Total: {metrics.total}</div>
                    <div>Last 24h: {metrics.last24Hours}</div>
                    <div>Last 7d: {metrics.last7Days}</div>
                  </div>
                </div>
                <div className="rounded-md border border-border bg-card p-3">
                  <div className="text-xs text-gray-400">By level</div>
                  <div className="mt-2 space-y-1 text-sm text-gray-200">
                    <div className="text-red-300">Errors: {levels.error}</div>
                    <div className="text-yellow-300">Warnings: {levels.warn}</div>
                    <div className="text-blue-300">Info: {levels.info}</div>
                  </div>
                </div>
                <div className="rounded-md border border-border bg-card p-3">
                  <div className="text-xs text-gray-400">Top sources</div>
                  {metrics.topSources.length === 0 ? (
                    <div className="mt-2 text-xs text-gray-500">No sources yet.</div>
                  ) : (
                    <div className="mt-2 space-y-1 text-xs text-gray-300">
                      {metrics.topSources.map((item: SystemLogMetrics["topSources"][number]) => (
                        <div key={item.source} className="flex items-center justify-between gap-2">
                          <span className="truncate">{item.source}</span>
                          <span className="text-gray-500">{item.count}</span>
                        </div>
                      ))}
