"use client";

import { useQuery, useMutation, useQueryClient, type UseMutationResult, type UseQueryResult } from "@tanstack/react-query";
import { useState, useMemo, useEffect, useCallback } from "react";
import { 
  getProducts, 
  countProducts, 
  createProduct, 
  updateProduct, 
  deleteProduct 
} from "@/features/products/api";
import type { 
  ProductWithImages, 
} from "@/features/products/types";
import type { DeleteResponse } from "@/shared/types/api";

// --- Queries ---

export interface UseProductsFilters {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}

export function useProducts(
  filters: UseProductsFilters,
  options: { enabled?: boolean } = {}
): UseQueryResult<ProductWithImages[], Error> {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products", filters],
    queryFn: () => getProducts(filters),
    enabled,
  });
}

export function useProductsCount(
  filters: UseProductsFilters,
  options: { enabled?: boolean } = {}
): UseQueryResult<number, Error> {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products-count", filters],
    queryFn: () => countProducts(filters),
    enabled,
  });
}

// --- Mutations ---

export function useCreateProductMutation(): UseMutationResult<unknown, Error, FormData, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (formData: FormData) => createProduct(formData),
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

export function useUpdateProductMutation(): UseMutationResult<ProductWithImages, Error, { id: string; data: Partial<ProductWithImages> | FormData }, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, data }): Promise<ProductWithImages> => {
      if (data instanceof FormData) {
        const response = await fetch(`/api/products/${id}`, {
          method: "PUT",
          body: data,
        });
        if (!response.ok) throw new Error("Failed to update product");
        return response.json() as Promise<ProductWithImages>;
      } else {
        return updateProduct(id, data);
      }
    },
    onSuccess: (data: ProductWithImages) => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products", data.id] });
    },
  });
}

export function useDeleteProductMutation(): UseMutationResult<DeleteResponse, Error, string, unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => deleteProduct(id) as Promise<DeleteResponse>,
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

export function useBulkDeleteProductsMutation(): UseMutationResult<{ success: boolean }, Error, string[], unknown> {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (ids: string[]): Promise<{ success: boolean }> => {
      const responses = await Promise.all(
        ids.map((id: string) => deleteProduct(id))
      );
      if (responses.some((r: { success: boolean }) => !r.success)) throw new Error("Failed to delete some products");
      return { success: true };
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products-count"] });
    },
  });
}

// --- Composite Hook ---

export interface UseProductDataProps {
  refreshTrigger?: number;
  initialCatalogFilter?: string | null;
  initialPageSize?: number | null;
  preferencesLoaded: boolean;
  currencyCode?: string | null;
  priceGroups?: unknown[];
  searchLanguage?: string | null;
}

export interface ProductDataHookResult {
  data: ProductWithImages[];
  totalPages: number;
  page: number;
  setPage: (p: number) => void;
  pageSize: number;
  setPageSize: (size: number) => void;
  search: string;
  setSearch: (s: string) => void;
  sku: string;
  setSku: (s: string) => void;
  minPrice: number | undefined;
  setMinPrice: (p: number | undefined) => void;
  maxPrice: number | undefined;
  setMaxPrice: (p: number | undefined) => void;
  startDate: string | undefined;
  setStartDate: (s: string | undefined) => void;
  endDate: string | undefined;
  setEndDate: (s: string | undefined) => void;
  catalogFilter: string;
  setCatalogFilter: (f: string) => void;
  loadError: Error | null;
  isLoading: boolean;
  isFetching: boolean;
  refresh: () => void;
}

export function useProductData({
  refreshTrigger,
  initialCatalogFilter,
  initialPageSize,
  preferencesLoaded,
  searchLanguage,
}: UseProductDataProps): ProductDataHookResult {
  const queryClient = useQueryClient();

  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize || 20);
  const [search, setSearch] = useState("");
  const [sku, setSku] = useState("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string | undefined>(undefined);
  const [endDate, setEndDate] = useState<string | undefined>(undefined);
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter || "all");

  useEffect(() => {
    if (preferencesLoaded) {
      if (initialCatalogFilter) setCatalogFilter(initialCatalogFilter);
      if (initialPageSize) setPageSize(initialPageSize);
    }
  }, [preferencesLoaded, initialCatalogFilter, initialPageSize]);

  const filters: UseProductsFilters = useMemo(() => ({
    search: search || undefined,
    sku: sku || undefined,
    minPrice,
    maxPrice,
    startDate: startDate || undefined,
    endDate: endDate || undefined,
    page,
    pageSize,
    catalogId: catalogFilter === "all" ? undefined : catalogFilter,
    searchLanguage: searchLanguage || undefined,
  }), [search, sku, minPrice, maxPrice, startDate, endDate, page, pageSize, catalogFilter, searchLanguage]);

  const productsQuery = useProducts(filters, { enabled: preferencesLoaded });
  const countQuery = useProductsCount(filters, { enabled: preferencesLoaded });

  const totalPages = useMemo(() => {
    const total = countQuery.data || 0;
    return Math.ceil(total / pageSize);
  }, [countQuery.data, pageSize]);

  const refresh = useCallback(() => {
    void queryClient.invalidateQueries({ queryKey: ["products"] });
    void queryClient.invalidateQueries({ queryKey: ["products-count"] });
  }, [queryClient]);

  // Invalidate when refreshTrigger changes
  useEffect(() => {
    if (refreshTrigger) {
      refresh();
    }
  }, [refreshTrigger, refresh]);

  return {
    data: productsQuery.data || [],
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    loadError: (productsQuery.error || countQuery.error),
    isLoading: productsQuery.isLoading || countQuery.isLoading,
    isFetching: productsQuery.isFetching || countQuery.isFetching,
    refresh,
  };
}

import { useState, useCallback, useRef, useEffect } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { ProductWithImages, ProductImageRecord } from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductImageSlot } from "@/features/products/types/products-ui";

const TOTAL_IMAGE_SLOTS = 15;

const normalizeImageLinks = (links?: string[] | null): string[] => {
  const next: string[] = new Array<string>(TOTAL_IMAGE_SLOTS).fill("");
  if (Array.isArray(links)) {
    links.slice(0, TOTAL_IMAGE_SLOTS).forEach((link: string, index: number) => {
      next[index] = typeof link === "string" ? link : "";
    });
  }
  return next;
};

const buildImageSlotsFromProduct = (
  product?: ProductWithImages,
): (ProductImageSlot | null)[] => {
  const slots: (ProductImageSlot | null)[] = Array.from(
    { length: TOTAL_IMAGE_SLOTS },
    () => null,
  );
  if (!product?.images?.length) return slots;
  product.images.slice(0, TOTAL_IMAGE_SLOTS).forEach((pImg: ProductImageRecord, index: number) => {
    if (pImg.imageFile) {
      slots[index] = {
        type: "existing",
        data: pImg.imageFile as ImageFileSelection,
        previewUrl: pImg.imageFile.filepath,
        slotId: pImg.imageFile.id,
      };
    }
  });
  return slots;
};

const createSlotId = (): string =>
  typeof crypto !== "undefined" && "randomUUID" in crypto
    ? crypto.randomUUID()
    : `${Date.now()}-${Math.random().toString(16).slice(2)}`;

export interface ProductImagesHookResult {
  imageSlots: (ProductImageSlot | null)[];
  imageLinks: string[];
  showFileManager: boolean;
  setShowFileManager: (show: boolean) => void;
  handleSlotImageChange: (file: File | null, index: number) => void;
  handleSlotFileSelect: (file: ImageFileSelection | null, index: number) => void;
  handleSlotDisconnectImage: (index: number) => Promise<void>;
  handleMultiImageChange: (files: File[]) => void;
  handleMultiFileSelect: (files: ImageFileSelection[]) => void;
  swapImageSlots: (fromIndex: number, toIndex: number) => void;
  setImageLinkAt: (index: number, value: string) => void;
  refreshFromProduct: (savedProduct: ProductWithImages) => void;
  setImagesReordering: (value: boolean) => void;
}

export function useProductImages(
  product?: ProductWithImages,
  initialImageLinks?: string[] | null,
): ProductImagesHookResult {
  const [imageSlots, setImageSlots] = useState<(ProductImageSlot | null)[]>(
    () => buildImageSlotsFromProduct(product),
  );
  const [imageLinks, setImageLinks] = useState<string[]>(() =>
    normalizeImageLinks(product?.imageLinks ?? initialImageLinks),
  );
  const [showFileManager, setShowFileManager] = useState(false);
  const objectUrlsRef = useRef<string[]>([]);
  const isReorderingRef = useRef(false);
  const pendingRefreshRef = useRef<ProductWithImages | null>(null);

  const queryClient = useQueryClient();
  const disconnectImageMutation = useMutation({
    mutationFn: async ({ productId, imageFileId }: { productId: string; imageFileId: string }): Promise<void> => {
      const res = await fetch(`/api/products/${productId}/images/${imageFileId}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to disconnect image");
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["products"] });
    }
  });

  // Effect to clean up object URLs when component unmounts or imageSlots change
  useEffect(() => {
    const currentObjectUrls = imageSlots
      .map((slot: ProductImageSlot | null): string | null => (slot?.type === "file" ? slot.previewUrl : null))
      .filter((url: string | null): url is string => Boolean(url));

    // Revoke old object URLs that are no longer in use
    const oldObjectUrls = objectUrlsRef.current.filter(
      (url: string) => !currentObjectUrls.includes(url),
    );
    oldObjectUrls.forEach((url: string) => URL.revokeObjectURL(url));

    // Update ref with current object URLs
    objectUrlsRef.current = currentObjectUrls;

    return () => {
      // Clean up all object URLs on unmount
      objectUrlsRef.current.forEach((url: string) => URL.revokeObjectURL(url));
      objectUrlsRef.current = [];
    };
  }, [imageSlots]);

  const handleSlotImageChange = useCallback(
    (file: File | null, index: number): void => {
      setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
        const newSlots = [...prevSlots];
        if (file) {
          // Revoke existing object URL if replacing an image
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = {
            type: "file",
            data: file,
            previewUrl: URL.createObjectURL(file),
            slotId: createSlotId(),
          };
        } else {
          // Revoke object URL if clearing the slot
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = null;
        }
        return newSlots;
      });
    },
    [],
  );

  const handleSlotFileSelect = useCallback(
    (file: ImageFileSelection | null, index: number): void => {
      setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
        const newSlots = [...prevSlots];
        if (file) {
          // Revoke object URL if replacing a file upload with an existing file
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = {
            type: "existing",
            data: file,
            previewUrl: file.filepath,
            slotId: file.id,
          };
        } else {
          // Revoke object URL if clearing the slot
          const existingSlot = newSlots[index];
          if (existingSlot?.type === "file") {
            URL.revokeObjectURL(existingSlot.previewUrl);
          }
          newSlots[index] = null;
        }
        return newSlots;
      });
      setShowFileManager(false);
    },
    [],
  );

  const handleSlotDisconnectImage = useCallback(
    async (index: number): Promise<void> => {
      const slotToClear = imageSlots[index];
      if (!slotToClear) return;

      setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
        const newSlots = [...prevSlots];
        newSlots[index] = null;
        return newSlots;
      });

      if (slotToClear.type === "existing" && product?.id) {
        try {
          await disconnectImageMutation.mutateAsync({
            productId: product.id,
            imageFileId: slotToClear.data.id,
          });
        } catch (error) {
          console.error("Failed to disconnect image from product:", error);
        }
      } else if (slotToClear.type === "file") {
        URL.revokeObjectURL(slotToClear.previewUrl);
      }
    },
    [imageSlots, product, disconnectImageMutation],
  );

  const setImageLinkAt = useCallback((index: number, value: string): void => {
    setImageLinks((prev: string[]) => {
      const next = [...prev];
      if (index < 0 || index >= next.length) return prev;
      next[index] = value;
      return next;
    });
  }, []);

  const handleMultiImageChange = useCallback((files: File[]): void => {
    setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "file",
              data: file,
              previewUrl: URL.createObjectURL(file),
              slotId: createSlotId(),
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
  }, []);

  const handleMultiFileSelect = useCallback((files: ImageFileSelection[]): void => {
    setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
      const newSlots = [...prevSlots];
      let fileIndex = 0;
      for (let i = 0; i < TOTAL_IMAGE_SLOTS && fileIndex < files.length; i++) {
        if (newSlots[i] === null) {
          const file = files[fileIndex];
          if (file) {
            newSlots[i] = {
              type: "existing",
              data: file,
              previewUrl: file.filepath,
              slotId: file.id,
            };
          }
          fileIndex++;
        }
      }
      return newSlots;
    });
    setShowFileManager(false);
  }, []);

  const swapImageSlots = useCallback((fromIndex: number, toIndex: number): void => {
    if (fromIndex === toIndex) return;
    if (fromIndex < 0 || fromIndex >= TOTAL_IMAGE_SLOTS) return;
    if (toIndex < 0 || toIndex >= TOTAL_IMAGE_SLOTS) return;

    setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
      const newSlots = [...prevSlots];
      const temp = newSlots[fromIndex];
      newSlots[fromIndex] = newSlots[toIndex]!;
      newSlots[toIndex] = temp!;
      return newSlots;
    });

    setImageLinks((prevLinks: string[]) => {
      const newLinks = [...prevLinks];
      const temp = newLinks[fromIndex];
      newLinks[fromIndex] = newLinks[toIndex]!;
      newLinks[toIndex] = temp!;
      return newLinks;
    });
  }, []);

  const applyRefresh = useCallback((savedProduct: ProductWithImages): void => {
    setImageSlots((prevSlots: (ProductImageSlot | null)[]) => {
      // Instead of replacing all slots, update only what changed
      // This prevents flickering by keeping existing references when possible
      const newSlots: (ProductImageSlot | null)[] = [...prevSlots];

      // Update slots with saved images
      savedProduct.images.slice(0, TOTAL_IMAGE_SLOTS).forEach((pImg: ProductImageRecord, index: number) => {
        if (pImg.imageFile) {
          const existingSlot = newSlots[index];
          // Only update if the image ID changed or slot was empty
          if (
            !existingSlot ||
            existingSlot.type !== "existing" ||
            existingSlot.slotId !== pImg.imageFile.id
          ) {
            newSlots[index] = {
              type: "existing",
              data: pImg.imageFile,
              previewUrl: pImg.imageFile.filepath,
              slotId: pImg.imageFile.id,
            };
          }
        }
      });

      // Clear slots beyond saved images count
      for (let i = savedProduct.images.length; i < TOTAL_IMAGE_SLOTS; i++) {
        if (newSlots[i]?.type === "file") {
          // Keep temporary file uploads that haven't been saved yet
          continue;
        }
        newSlots[i] = null;
      }

      return newSlots;
    });
    setImageLinks(normalizeImageLinks(savedProduct.imageLinks));
  }, []);

  const setImagesReordering = useCallback(
    (value: boolean): void => {
      isReorderingRef.current = value;
      if (!value && pendingRefreshRef.current) {
        const pending = pendingRefreshRef.current;
        pendingRefreshRef.current = null;
        applyRefresh(pending);
      }
    },
    [applyRefresh],
  );

  // Function to refresh state from product (e.g. after save)
  const refreshFromProduct = useCallback(
    (savedProduct: ProductWithImages): void => {
      if (isReorderingRef.current) {
        pendingRefreshRef.current = savedProduct;
        if (process.env.NODE_ENV !== "production") {
          console.info("[product-images] Refresh deferred during reorder");
        }
        return;
      }
      applyRefresh(savedProduct);
    },
    [applyRefresh],
  );

  return {
    imageSlots,
    imageLinks,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    refreshFromProduct,
    setImagesReordering,
  };
}

"use client";
import { ProfilerOnRenderCallback, useCallback, useEffect, useMemo, useState } from "react";

import dynamic from "next/dynamic";
import { useSearchParams } from "next/navigation";
import { useQueryClient } from "@tanstack/react-query";

import { useToast } from "@/shared/ui";
import { ProductTableSkeleton } from "@/features/products/components/list/ProductTableSkeleton";
import {
  useProductData,
  useBulkDeleteProductsMutation,
} from "@/features/products/hooks/useProductData";
import { useProductOperations } from "@/features/products/hooks/useProductOperations";
import { useIntegrationOperations } from "@/features/integrations/hooks/useIntegrationOperations";
import { useCatalogSync } from "@/features/products/hooks/useCatalogSync";
import { useUserPreferences } from "@/features/products/hooks/useUserPreferences";
import { ProductListPanel } from "@/features/products/components/ProductListPanel";
import { ProductModals } from "@/features/products/components/ProductModals";
import { columns } from "@/features/products/components/list/ProductColumns";
import DebugPanel from "@/features/products/components/DebugPanel";
import type { RowSelectionState } from "@tanstack/react-table";
import type { ProductDraft } from "@/features/products/types/drafts";
import type { ProductWithImages } from "@/features/products/types";
import { logger } from "@/shared/utils/logger";
import { useDrafts, draftKeys } from "@/features/drafter/hooks/useDrafts";
import { getProducts } from "@/features/products/api";

const SelectIntegrationModal = dynamic(
  () => import("@/features/integrations/components/listings/SelectIntegrationModal").then((mod) => ({ default: mod.SelectIntegrationModal })),
  { ssr: false }
);

export function AdminProductsPage(): React.JSX.Element {
  const searchParams = useSearchParams();
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const [isDebugOpen, setIsDebugOpen] = useState(false);
  const { toast } = useToast();
  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});
  const [createDraft, setCreateDraft] = useState<ProductDraft | null>(null);
  const queryClient = useQueryClient();

  const { data: allDrafts = [] } = useDrafts();
  const activeDrafts = useMemo(() => allDrafts.filter((d: ProductDraft) => d.active !== false), [allDrafts]);

  // Load user preferences
  const {
    preferences,
    loading: preferencesLoading,
    setNameLocale: updateNameLocale,
    setCatalogFilter: updateCatalogFilter,
    setCurrencyCode: updateCurrencyCode,
    setPageSize: updatePageSize,
  } = useUserPreferences();

  // Load catalog and currency data first
  const {
    catalogs,
    currencyCode,
    setCurrencyCode,
    currencyOptions,
    priceGroups,
    languageOptions,
    fallbackNameLocale,
  } = useCatalogSync(preferences.catalogFilter || "all");

  const {
    data,
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    loadError,
    isLoading,
  } = useProductData({
    refreshTrigger,
    initialCatalogFilter: preferences.catalogFilter,
    initialPageSize: preferences.pageSize,
    preferencesLoaded: !preferencesLoading,
    currencyCode,
    priceGroups,
    searchLanguage: preferences.nameLocale,
  });

  const {
    isCreateOpen,
    setIsCreateOpen,
    initialSku,
    editingProduct,
    setEditingProduct,
    lastEditedId,
    actionError,
    setActionError,
    handleOpenCreateModal,
    handleOpenCreateFromDraft,
    handleCreateSuccess,
    handleEditSuccess,
    handleEditSave,
  } = useProductOperations(setRefreshTrigger);

  const {
    integrationsProduct,
    setIntegrationsProduct,
    showListProductModal,
    setShowListProductModal,
    listProductPreset,
    setListProductPreset,
    integrationBadgeIds,
    integrationBadgeStatuses,
    exportSettingsProduct,
    setExportSettingsProduct,
    refreshListingBadges,
    handleListProductSuccess: baseHandleListProductSuccess,
  } = useIntegrationOperations();

  // Initialize currency code from preferences
  useEffect(() => {
    if (!preferencesLoading && preferences.currencyCode) {
      setCurrencyCode(preferences.currencyCode);
    }
  }, [preferencesLoading, preferences.currencyCode, setCurrencyCode]);

  const handleOpenEditModal = useCallback((product: ProductWithImages) => {
    setEditingProduct(product);
  }, [setEditingProduct]);

  const handleOpenCreate = useCallback(() => {
    setCreateDraft(null);
    void handleOpenCreateModal();
  }, [handleOpenCreateModal]);

  const handleOpenIntegrationsModal = useCallback((product: ProductWithImages) => {
    setIntegrationsProduct(product);
  }, [setIntegrationsProduct]);

  const handleOpenExportSettings = useCallback((product: ProductWithImages) => {
    setExportSettingsProduct(product);
  }, [setExportSettingsProduct]);

  const handleSetPage = useCallback((p: number) => {
    setPage(p);
  }, [setPage]);

  const handleSetPageSize = useCallback((size: number) => {
    setPageSize(size);
    updatePageSize(size);
  }, [setPageSize, updatePageSize]);

  const handleSetNameLocale = useCallback((locale: "name_en" | "name_pl" | "name_de") => {
    updateNameLocale(locale);
  }, [updateNameLocale]);

  const handleSetCurrencyCode = useCallback((code: string) => {
    setCurrencyCode(code);
    updateCurrencyCode(code);
  }, [setCurrencyCode, updateCurrencyCode]);

  const handleSetCatalogFilter = useCallback((filter: string) => {
    setCatalogFilter(filter);
    updateCatalogFilter(filter);
  }, [setCatalogFilter, updateCatalogFilter]);

  useEffect(() => {
    if (!languageOptions.length) return;
    const allowed = new Set(languageOptions.map((option: { label: string; value: "name_en" | "name_pl" | "name_de" }) => option.value));
    if (allowed.has(preferences.nameLocale)) return;
    const nextLocale = (fallbackNameLocale && allowed.has(fallbackNameLocale))
      ? fallbackNameLocale
      : languageOptions[0]!.value;
    updateNameLocale(nextLocale);
  }, [languageOptions, fallbackNameLocale, preferences.nameLocale, updateNameLocale]);

  const handleCreateFromDraft = useCallback((draftId: string): void => {
    const run = async (): Promise<void> => {
      try {
        const draft = await queryClient.fetchQuery({
            queryKey: draftKeys.detail(draftId),
            queryFn: async () => {
                const res = await fetch(`/api/drafts/${draftId}`);
                if (!res.ok) throw new Error("Failed to load draft");
                return (await res.json()) as ProductDraft;
            }
        });
        setCreateDraft(draft);
        handleOpenCreateFromDraft(draft);
        toast(`Creating product from draft: ${draft.name}`, { variant: "success" });
      } catch (error) {
        console.error("Failed to load draft:", error);
        toast("Failed to load draft template", { variant: "error" });
      }
    };
    void run();
  }, [handleOpenCreateFromDraft, toast, queryClient]);

  const handleCloseCreate = useCallback(() => {
    setIsCreateOpen(false);
    setCreateDraft(null);
  }, [setIsCreateOpen]);
  const handleDismissActionError = useCallback(() => {
    setActionError(null);
  }, [setActionError]);
  const handleCloseEdit = useCallback(() => setEditingProduct(null), [setEditingProduct]);
  const handleCloseIntegrations = useCallback(() => {
    setIntegrationsProduct(null);
    setShowListProductModal(false);
  }, [setIntegrationsProduct, setShowListProductModal]);
  const handleCloseListProduct = useCallback(() => {
    setShowListProductModal(false);
    setListProductPreset(null);
  }, [setShowListProductModal, setListProductPreset]);

  const handleListProductSuccess = useCallback(() => {
    setListProductPreset(null);
    baseHandleListProductSuccess();
  }, [setListProductPreset, baseHandleListProductSuccess]);

  const handleStartListing = useCallback((integrationId: string, connectionId: string) => {
    setListProductPreset({ integrationId, connectionId });
    setShowListProductModal(true);
  }, [setListProductPreset, setShowListProductModal]);

  // Mass listing state
  const [massListIntegration, setMassListIntegration] = useState<{ integrationId: string; connectionId: string } | null>(null);
  const [massListProductIds, setMassListProductIds] = useState<string[]>([]);
  const [isMassListing, setIsMassListing] = useState(false);

  // State for integration selection modal
  const [showIntegrationModal, setShowIntegrationModal] = useState(false);

  const handleCloseIntegrationModal = useCallback(() => {
    setShowIntegrationModal(false);
    setIsMassListing(false);
  }, []);

  const getRowId = useCallback((row: ProductWithImages) => row.id, []);

  const handleSelectIntegrationFromModal = useCallback((integrationId: string, connectionId: string) => {
    setShowIntegrationModal(false);
    if (isMassListing) {
       const ids = Object.keys(rowSelection).filter((id: string) => rowSelection[id]);
       setMassListProductIds(ids);
       setMassListIntegration({ integrationId, connectionId });
    }
  }, [isMassListing, rowSelection]);

  const handleCloseMassList = useCallback(() => {
    setMassListIntegration(null);
    setMassListProductIds([]);
    setIsMassListing(false);
  }, []);

  const handleMassListSuccess = useCallback(() => {
    setMassListIntegration(null);
    setMassListProductIds([]);
    setIsMassListing(false);
    setRefreshTrigger((prev: number) => prev + 1);
    toast("Products listed successfully.", { variant: "success" });
    void refreshListingBadges();
  }, [toast, refreshListingBadges]);

  const handleAddToMarketplace = useCallback(() => {
    setIsMassListing(true);
    setShowIntegrationModal(true);
  }, []);

  const [loadingGlobalSelection, setLoadingGlobalSelection] = useState(false);

  const bulkDeleteMutation = useBulkDeleteProductsMutation();

  const handleSelectAllGlobal = useCallback(async () => {
    setLoadingGlobalSelection(true);
    try {
      const filters = {
        search,
        sku,
        minPrice,
        maxPrice,
        startDate: startDate || undefined,
        endDate: endDate || undefined,
        catalogId: catalogFilter === "all" ? undefined : catalogFilter,
        searchLanguage: preferences.nameLocale,
      };

      const allProducts = await queryClient.fetchQuery({
        queryKey: ["products-all", filters],
        queryFn: () => getProducts(filters)
      });

      const newSelection: RowSelectionState = {};
      allProducts.forEach((p: ProductWithImages) => {
        newSelection[p.id] = true;
      });
      setRowSelection(newSelection);
      toast(`Selected ${allProducts.length} products.`, { variant: "success" });
    } catch (error) {
      console.error(error);
      toast("Failed to select all products", { variant: "error" });
    } finally {
      setLoadingGlobalSelection(false);
    }
  }, [search, sku, minPrice, maxPrice, startDate, endDate, catalogFilter, preferences.nameLocale, toast, queryClient]);

  const handleMassDelete = useCallback(async () => {
    logger.log("Mass delete initiated.");
    const selectedProductIds = Object.keys(rowSelection).filter(
      (id: string) => rowSelection[id]
    );

    if (selectedProductIds.length === 0) return;

    if (
      window.confirm(
        `Are you sure you want to delete ${selectedProductIds.length} selected products?`
      )
    ) {
      try {
        await bulkDeleteMutation.mutateAsync(selectedProductIds);
        toast("Selected products deleted successfully.", { variant: "success" });
        setRowSelection({});
        setRefreshTrigger((prev: number) => prev + 1);
      } catch (error) {
        logger.error("Error during mass deletion:", error);
        setActionError(error instanceof Error ? error.message : "An error occurred during deletion.");
      }
    }
  }, [rowSelection, setActionError, toast, bulkDeleteMutation]);

  useEffect(() => {
    setIsDebugOpen(searchParams.get("debug") === "true");
  }, [searchParams]);

  useEffect(() => {
    if (!lastEditedId) return;
    if (data.length === 0) return;
    const target = document.querySelector(`[data-row-id="${lastEditedId}"]`);
    if (target instanceof HTMLElement) {
      requestAnimationFrame(() => {
        target.scrollIntoView({ behavior: "smooth", block: "center" });
      });
    }
  }, [data, lastEditedId]);

  const tableSkeleton = useMemo(
    () => <ProductTableSkeleton rows={pageSize} />,
    [pageSize]
  );

  const handleProductsTableRender = useCallback<ProfilerOnRenderCallback>(
    (_id: string, _phase: "mount" | "update" | "nested-update", actualDuration: number, _baseDuration: number, _startTime: number, commitTime: number) => {
      if (!isDebugOpen || typeof performance === "undefined") return;
      performance.measure("products:tableRender", {
        start: commitTime - actualDuration,
        end: commitTime,
      });
    },
    [isDebugOpen]
  );

  return (
    <>
      {isDebugOpen && <DebugPanel />}
      <ProductListPanel
        onCreateProduct={handleOpenCreate}
        onCreateFromDraft={handleCreateFromDraft}
        activeDrafts={activeDrafts}
        page={page}
        totalPages={totalPages}
        setPage={handleSetPage}
        pageSize={pageSize}
        setPageSize={handleSetPageSize}
        nameLocale={preferences.nameLocale}
        setNameLocale={handleSetNameLocale}
        languageOptions={languageOptions}
        currencyCode={currencyCode}
        setCurrencyCode={handleSetCurrencyCode}
        currencyOptions={currencyOptions}
        catalogFilter={catalogFilter}
        setCatalogFilter={handleSetCatalogFilter}
        catalogs={catalogs}
        loadError={loadError?.message || null}
        actionError={actionError}
        onDismissActionError={handleDismissActionError}
        search={search}
        setSearch={setSearch}
        sku={sku}
        setSku={setSku}
        minPrice={minPrice}
        setMinPrice={setMinPrice}
        maxPrice={maxPrice}
        setMaxPrice={setMaxPrice}
        startDate={startDate || ""}
        setStartDate={setStartDate}
        endDate={endDate || ""}
        setEndDate={setEndDate}
        data={data}
        rowSelection={rowSelection}
        setRowSelection={setRowSelection}
        onSelectAllGlobal={handleSelectAllGlobal}
        loadingGlobal={loadingGlobalSelection}
        onDeleteSelected={handleMassDelete}
        onAddToMarketplace={handleAddToMarketplace}
        handleProductsTableRender={handleProductsTableRender}
        tableColumns={columns}
        setRefreshTrigger={setRefreshTrigger}
        productNameKey={preferences.nameLocale}
        priceGroups={priceGroups}
        onProductNameClick={handleOpenEditModal}
        onProductEditClick={handleOpenEditModal}
        onIntegrationsClick={handleOpenIntegrationsModal}
        onExportSettingsClick={handleOpenExportSettings}
        integrationBadgeIds={integrationBadgeIds}
        integrationBadgeStatuses={integrationBadgeStatuses}
        getRowId={getRowId}
        isLoading={isLoading}
        skeletonRows={tableSkeleton}
      />
      <ProductModals
        isCreateOpen={isCreateOpen}
        initialSku={initialSku}
        createDraft={createDraft}
        onCloseCreate={handleCloseCreate}
        onCreateSuccess={() => {
          handleCreateSuccess();
          setCreateDraft(null);
        }}
        editingProduct={editingProduct}
        onCloseEdit={handleCloseEdit}
        onEditSuccess={handleEditSuccess}
        onEditSave={handleEditSave}
        integrationsProduct={integrationsProduct}
        onCloseIntegrations={handleCloseIntegrations}
        onStartListing={handleStartListing}
        showListProductModal={showListProductModal}
        onCloseListProduct={handleCloseListProduct}
        onListProductSuccess={handleListProductSuccess}
        listProductPreset={listProductPreset}
        exportSettingsProduct={exportSettingsProduct}
        onCloseExportSettings={() => setExportSettingsProduct(null)}
        onListingsUpdated={() => void refreshListingBadges()}
        massListIntegration={massListIntegration}
        massListProductIds={massListProductIds}
        onCloseMassList={handleCloseMassList}
        onMassListSuccess={handleMassListSuccess}
      />

      {showIntegrationModal && (
        <SelectIntegrationModal
          onClose={handleCloseIntegrationModal}
          onSelect={handleSelectIntegrationFromModal}
        />
      )}
    </>
  );
}

